const ADJ_THEORY_HTML = "\n<div class=\"glass rounded-2xl p-4 mb-4\" style=\"border-left:4px solid var(--accent)\">\n  <div class=\"font-800 text-dark2 mb-2\">🌟 TỔNG QUAN — Tính từ trong tiếng Anh (Adjective)</div>\n  <div class=\"text-sm text-soft\">Tính từ (Adjective — Adj) là những từ dùng để miêu tả đặc điểm, đặc tính hoặc tính cách của con người, sự vật, hiện tượng. Tính từ còn đóng vai trò bổ nghĩa cho danh từ, đại từ hoặc động từ tình thái.</div>\n  <div class=\"ex-card mt-2\">My father is very <b>handsome</b>.<br><span style=\"color:var(--accent);font-size:13px\">→ Bố tôi rất đẹp trai.</span></div>\n  <div class=\"ex-card mt-2\">The exam is too <b>difficult</b> for us to get high marks.<br><span style=\"color:var(--accent);font-size:13px\">→ Bài thi quá khó để chúng tôi đạt điểm cao.</span></div>\n</div>\n\n<details open class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#457B9D,#5b9bc4);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">1</span> Vị trí của tính từ trong câu\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2 glass rounded-2xl p-4\">\n    <div class=\"rule-row\"><span class=\"suffix-pill\">1.1</span><span class=\"text-dark2\">Tính từ đứng trước danh từ</span></div>\n    <div class=\"text-sm text-soft mt-1\">Tính từ đứng trước danh từ để bổ nghĩa, giúp danh từ được miêu tả chi tiết, cụ thể hơn.</div>\n    <div class=\"ex-card mt-2\">A <b>lovely</b> baby <span style=\"color:var(--text-soft)\">(một em bé dễ thương)</span><br>A <b>wonderful</b> trip <span style=\"color:var(--text-soft)\">(một chuyến đi tuyệt vời)</span></div>\n    <div class=\"mt-3 p-3 rounded-xl\" style=\"background:#fff3cd;border-left:3px solid #ffc107;font-size:13px\">⚠️ Khi dùng từ 2 tính từ trở lên để miêu tả một danh từ: nếu các tính từ CÙNG LOẠI → phân cách bằng dấu phẩy; nếu KHÁC LOẠI → xếp cạnh nhau theo đúng trật tự OSASCOMP (xem mục 2).</div>\n\n    <div class=\"rule-row mt-3\"><span class=\"suffix-pill\">1.2</span><span class=\"text-dark2\">Tính từ đứng sau động từ tình thái/tri giác (linking verbs)</span></div>\n    <div class=\"text-sm text-soft mt-1\">Các động từ như feel, find, seem, sound, taste, smell, look, appear, remain, keep/stay, become/get... được theo sau bởi TÍNH TỪ (không phải trạng từ) để mô tả chủ ngữ.</div>\n    <div class=\"ex-card mt-2\">Everything <b>seems</b> perfect. <span style=\"color:var(--accent)\">→ Mọi thứ dường như hoàn hảo.</span><br>She <b>looks</b> happier than yesterday. <span style=\"color:var(--accent)\">→ Cô ấy trông vui vẻ hơn hôm qua.</span></div>\n\n    <div class=\"rule-row mt-3\"><span class=\"suffix-pill\">1.3</span><span class=\"text-dark2\">Tính từ đứng sau đại từ bất định</span></div>\n    <div class=\"text-sm text-soft mt-1\">something, nothing, anything, someone/somebody, anyone/anybody, everyone/everybody, no one/nobody + Adj.</div>\n    <div class=\"ex-card mt-2\">Is there anything <b>new</b>? <span style=\"color:var(--accent)\">→ Có gì mới không?</span><br>I met someone <b>strange</b> standing in front of your gate this morning. <span style=\"color:var(--accent)\">→ Sáng nay tôi gặp một người lạ mặt đứng trước cổng nhà bạn.</span></div>\n\n    <div class=\"rule-row mt-3\"><span class=\"suffix-pill\">1.4</span><span class=\"text-dark2\">Tính từ đứng sau trạng từ</span></div>\n    <div class=\"text-sm text-soft mt-1\">Trạng từ (thường là trạng từ chỉ mức độ) đứng TRƯỚC tính từ để bổ sung, làm rõ nghĩa hơn cho tính từ.</div>\n    <div class=\"ex-card mt-2\">She runs really <b>fast</b>. <span style=\"color:var(--accent)\">→ Cô ấy chạy thực sự nhanh.</span><br>He speaks English extremely <b>fluent</b>. <span style=\"color:var(--accent)\">→ Anh ấy nói tiếng Anh hết sức trôi chảy.</span></div>\n\n    <div class=\"rule-row mt-3\"><span class=\"suffix-pill\">1.5</span><span class=\"text-dark2\">Tính từ đứng sau \"to be\"</span></div>\n    <div class=\"text-sm text-soft mt-1\">Cấu trúc \"to be + tính từ\" miêu tả hoặc chỉ đặc điểm của danh từ/chủ từ.</div>\n    <div class=\"ex-card mt-2\">She is <b>kind</b> and <b>generous</b>. <span style=\"color:var(--accent)\">→ Cô ấy tốt bụng và hào hiệp.</span><br>The book is very <b>interesting</b> to me. <span style=\"color:var(--accent)\">→ Cuốn sách rất thú vị với tôi.</span></div>\n  </div>\n</details>\n\n<details class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#e63946,#ff8fa3);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">OSASCOMP</span> 2. Trật tự tính từ đứng trước danh từ\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\">\n    <div class=\"text-center font-800 text-dark2 mb-3\" style=\"font-size:18px;letter-spacing:2px\">O – S – A – S – C – O – M – P</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:600px\">\n      <thead><tr style=\"background:rgba(69,123,157,.1)\"><th style=\"padding:8px;text-align:left\">#</th><th style=\"padding:8px;text-align:left\">Nhóm</th><th style=\"padding:8px;text-align:left\">Ví dụ tính từ</th></tr></thead>\n      <tbody>\n        <tr><td style=\"padding:8px\">1</td><td style=\"padding:8px\"><b style=\"color:var(--accent)\">Opinion</b> — Nhận xét</td><td style=\"padding:8px;color:var(--text-soft)\">useful, beautiful, interesting, lovely, delicious, handsome, glorious, luxurious…</td></tr>\n        <tr><td style=\"padding:8px\">2</td><td style=\"padding:8px\"><b style=\"color:var(--accent)\">Size</b> — Kích cỡ</td><td style=\"padding:8px;color:var(--text-soft)\">big, small, large, huge, tiny, long, short, tall...</td></tr>\n        <tr><td style=\"padding:8px\">3</td><td style=\"padding:8px\"><b style=\"color:var(--accent)\">Age</b> — Tuổi tác</td><td style=\"padding:8px;color:var(--text-soft)\">old, young, new, brand-new, ancient, modern…</td></tr>\n        <tr><td style=\"padding:8px\">4</td><td style=\"padding:8px\"><b style=\"color:var(--accent)\">Shape</b> — Hình dáng</td><td style=\"padding:8px;color:var(--text-soft)\">round, triangle, cubic, heart-shaped, flat, square...</td></tr>\n        <tr><td style=\"padding:8px\">5</td><td style=\"padding:8px\"><b style=\"color:var(--accent)\">Color</b> — Màu sắc</td><td style=\"padding:8px;color:var(--text-soft)\">black, red, white, blue, yellow, cream, violet, purple, navy blue, magenta, brick red, emerald, jet black…</td></tr>\n        <tr><td style=\"padding:8px\">6</td><td style=\"padding:8px\"><b style=\"color:var(--accent)\">Origin</b> — Nguồn gốc</td><td style=\"padding:8px;color:var(--text-soft)\">Vietnamese, English, Indian, Thai, German, American…</td></tr>\n        <tr><td style=\"padding:8px\">7</td><td style=\"padding:8px\"><b style=\"color:var(--accent)\">Material</b> — Chất liệu</td><td style=\"padding:8px;color:var(--text-soft)\">silk, gold, silver, wooden, metal, plastic, leather, glass, concrete, ivory…</td></tr>\n        <tr><td style=\"padding:8px\">8</td><td style=\"padding:8px\"><b style=\"color:var(--accent)\">Purpose</b> — Mục đích</td><td style=\"padding:8px;color:var(--text-soft)\">sitting, sleeping, wedding, waiting…</td></tr>\n      </tbody>\n    </table>\n    <div class=\"ex-card mt-3\">A <b>beautiful young</b> girl <span style=\"color:var(--text-soft)\">(một cô gái trẻ đẹp)</span><br>A <b>luxurious gold</b> watch <span style=\"color:var(--text-soft)\">(một chiếc đồng hồ bằng vàng sang trọng)</span></div>\n    <div class=\"mt-3 p-3 rounded-xl\" style=\"background:#d4edda;border-left:3px solid #2ecc71;font-size:13px\">✅ <b>Mẹo nhớ nhanh:</b> \"Ý — Kích — Tuổi — Hình — Màu — Gốc — Liệu — Đích\" (Opinion → Size → Age → Shape → Color → Origin → Material → Purpose).</div>\n    <div class=\"mt-2 p-3 rounded-xl\" style=\"background:#fff3cd;border-left:3px solid #ffc107;font-size:13px\">⚠️ Ngoài 8 nhóm trên, khi một DANH TỪ được dùng làm từ phân loại đứng ngay trước danh từ chính (school trip, office environment, battery life…), nó luôn đứng ở vị trí gần danh từ chính nhất — sau tất cả các tính từ mô tả (Opinion, Age…).</div>\n  </div>\n</details>\n\n<details class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#457B9D,#5b9bc4);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">3</span> Cách nhận biết tính từ (đuôi thường gặp)\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\">\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:520px\">\n      <tbody>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-able</span></td><td style=\"padding:6px;color:var(--text-soft)\">capable, comfortable, considerable…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ous</span></td><td style=\"padding:6px;color:var(--text-soft)\">dangerous, poisonous, humorous…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ive</span></td><td style=\"padding:6px;color:var(--text-soft)\">aggressive, passive, active…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ful</span></td><td style=\"padding:6px;color:var(--text-soft)\">stressful, careful, beautiful…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-less</span></td><td style=\"padding:6px;color:var(--text-soft)\">careless, useless, harmless…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ly</span></td><td style=\"padding:6px;color:var(--text-soft)\">friendly, costly, lovely…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-y</span></td><td style=\"padding:6px;color:var(--text-soft)\">sunny, rainy, windy…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-al</span></td><td style=\"padding:6px;color:var(--text-soft)\">political, physical, historical…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ed</span></td><td style=\"padding:6px;color:var(--text-soft)\">bored, excited, interested…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ible</span></td><td style=\"padding:6px;color:var(--text-soft)\">possible, responsible, flexible…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ent</span></td><td style=\"padding:6px;color:var(--text-soft)\">confident, different, dependent…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ant</span></td><td style=\"padding:6px;color:var(--text-soft)\">important, significant, brilliant…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ic</span></td><td style=\"padding:6px;color:var(--text-soft)\">economic, specific, iconic…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ing</span></td><td style=\"padding:6px;color:var(--text-soft)\">interesting, boring, exciting…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-some</span></td><td style=\"padding:6px;color:var(--text-soft)\">handsome, troublesome…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-like</span></td><td style=\"padding:6px;color:var(--text-soft)\">childlike, dreamlike</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ary</span></td><td style=\"padding:6px;color:var(--text-soft)\">necessary, primary, customary, imaginary…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ish</span></td><td style=\"padding:6px;color:var(--text-soft)\">childish, selfish, reddish…</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">-ern</span></td><td style=\"padding:6px;color:var(--text-soft)\">Western, Eastern…</td></tr>\n      </tbody>\n    </table>\n  </div>\n</details>\n\n<details class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#2ecc71,#7bd88f);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">4</span> Cách thành lập tính từ\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\">\n    <div class=\"font-700 text-dark2 mb-2\">4.1. Thêm hậu tố (Suffix)</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:560px\">\n      <thead><tr style=\"background:rgba(69,123,157,.1)\"><th style=\"padding:6px;text-align:left\">Quy tắc</th><th style=\"padding:6px;text-align:left\">Ví dụ</th></tr></thead>\n      <tbody>\n        <tr><td style=\"padding:6px\">N + ly → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">friend+ly=friendly (thân thiện); love+ly=lovely (đáng yêu)</td></tr>\n        <tr><td style=\"padding:6px\">N + ful → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">care+ful=careful (cẩn thận); success+ful=successful (thành công)</td></tr>\n        <tr><td style=\"padding:6px\">N + less → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">home+less=homeless (vô gia cư); hope+less=hopeless (vô vọng)</td></tr>\n        <tr><td style=\"padding:6px\">N + ic → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">economy+ic=economic; history+ic=historic</td></tr>\n        <tr><td style=\"padding:6px\">N + able → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">reason+able=reasonable; comfort+able=comfortable</td></tr>\n        <tr><td style=\"padding:6px\">N + ous → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">danger+ous=dangerous; industry+ous=industrious</td></tr>\n        <tr><td style=\"padding:6px\">N + some → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">trouble+some=troublesome; hand+some=handsome</td></tr>\n        <tr><td style=\"padding:6px\">N + al → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">nation+al=national; nature+al=natural</td></tr>\n        <tr><td style=\"padding:6px\">N + ing/ed → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">interest+ing/ed=interesting/interested; bore+ing/ed=boring/bored</td></tr>\n        <tr><td style=\"padding:6px\">N + ern → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">West+ern=Western; South+ern=Southern</td></tr>\n        <tr><td style=\"padding:6px\">N + y → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">rain+y=rainy; sun+y=sunny</td></tr>\n        <tr><td style=\"padding:6px\">N + ible → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">response+ible=responsible</td></tr>\n        <tr><td style=\"padding:6px\">V + ent → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">depend+ent=dependent</td></tr>\n        <tr><td style=\"padding:6px\">V/N + ive → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">impress+ive=impressive; expense+ive=expensive</td></tr>\n        <tr><td style=\"padding:6px\">N + like → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">child+like=childlike; god+like=godlike</td></tr>\n        <tr><td style=\"padding:6px\">N + ish → Adj</td><td style=\"padding:6px;color:var(--text-soft)\">fool+ish=foolish; self+ish=selfish</td></tr>\n      </tbody>\n    </table>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">4.2. Thêm tiền tố (Prefix)</div>\n    <div class=\"text-sm text-soft mb-2\">Tiền tố phổ biến: un-, dis-, in-, im-, il-, ir-, non-, over-, under-, pre-, post-, bi-, multi-...</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:560px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:15%\"><b style=\"color:var(--accent)\">un-</b></td><td style=\"padding:6px;color:var(--text-soft)\">phủ định/ngược lại — unkind, unfriendly, unhappy, unclear, unhealthy</td></tr>\n        <tr><td style=\"padding:6px\"><b style=\"color:var(--accent)\">dis-</b></td><td style=\"padding:6px;color:var(--text-soft)\">phủ định — disagree, dislike, disrespect, disapprove, disbelieve</td></tr>\n        <tr><td style=\"padding:6px\"><b style=\"color:var(--accent)\">in-/im-/il-/ir-</b></td><td style=\"padding:6px;color:var(--text-soft)\">phủ định — incomplete, impossible, illegal, irregular, irresponsible</td></tr>\n        <tr><td style=\"padding:6px\"><b style=\"color:var(--accent)\">non-</b></td><td style=\"padding:6px;color:var(--text-soft)\">không/thiếu — nonstop, nonprofit, nonfiction, nonviolent, nonessential</td></tr>\n        <tr><td style=\"padding:6px\"><b style=\"color:var(--accent)\">over-</b></td><td style=\"padding:6px;color:var(--text-soft)\">vượt mức — overconfident, overexcited, overpriced, overrated, overused</td></tr>\n        <tr><td style=\"padding:6px\"><b style=\"color:var(--accent)\">under-</b></td><td style=\"padding:6px;color:var(--text-soft)\">thiếu/dưới mức — undercooked, underpaid, underdeveloped, underrepresented, undersized</td></tr>\n        <tr><td style=\"padding:6px\"><b style=\"color:var(--accent)\">pre-/post-</b></td><td style=\"padding:6px;color:var(--text-soft)\">trước/sau — prehistoric, prewar, postgraduate, postwar, preseason</td></tr>\n        <tr><td style=\"padding:6px\"><b style=\"color:var(--accent)\">bi-/multi-</b></td><td style=\"padding:6px;color:var(--text-soft)\">hai/nhiều — bilingual, bicolor, multiethnic, multifunctional, bipartisan</td></tr>\n      </tbody>\n    </table>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">4.3. Danh từ + Quá khứ phân từ (N + PII)</div>\n    <div class=\"ex-card\">Handmade (hand+made) - làm thủ công; Heartbroken (heart+broken) - đau lòng; Sunburned (sun+burned) - cháy nắng; Homesick (home+sick) - nhớ nhà; Tongue-tied (tongue+tied) - không thể nói được; Mass-produced (mass+produced) - sản xuất hàng loạt; Snow-covered (snow+covered) - bị bao phủ bởi tuyết</div>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">4.4. WELL/ILL + Quá khứ phân từ</div>\n    <div class=\"rule-row\"><span class=\"suffix-pill\">WELL</span><span class=\"text-dark2\">Well-known, well-educated, well-behaved, well-organized, well-developed, well-dressed, well-informed, well-prepared, well-written, well-balanced</span></div>\n    <div class=\"rule-row mt-2\"><span class=\"suffix-pill\">ILL</span><span class=\"text-dark2\">Ill-treated, ill-tempered, ill-fated, ill-prepared, ill-advised, ill-informed, ill-equipped, ill-gotten, ill-mannered, ill-conceived</span></div>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">4.5. Phân từ dùng như tính từ</div>\n    <div class=\"text-sm text-soft\">V-ing (hiện tại phân từ) chỉ nghĩa CHỦ ĐỘNG — đứng trước danh từ hoặc sau \"to be\": <i>The growing plant makes me happier.</i> (Cái cây đang lớn làm tôi hạnh phúc hơn)</div>\n    <div class=\"text-sm text-soft mt-1\">V-ed/V3 (quá khứ phân từ) chỉ nghĩa BỊ ĐỘNG — đứng trước danh từ hoặc sau \"to be\": <i>The packed lunch was thrown away because she was allergic to peanuts.</i> (Túi đồ ăn trưa được đóng gói đã bị vứt đi vì bạn ấy bị dị ứng với lạc)</div>\n    <div class=\"mt-3 p-3 rounded-xl\" style=\"background:#f8d7da;border-left:3px solid #e74c3c;font-size:13px\">❌ Lỗi thường gặp: nhầm lẫn giữa -ing (vật/việc GÂY RA cảm xúc: boring, interesting, exciting, confusing, tiring…) và -ed (người CẢM THẤY cảm xúc đó: bored, interested, excited, confused, tired…).</div>\n  </div>\n</details>\n\n<details class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#6a4c93,#a084c9);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">5</span> Chức năng của tính từ\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2 glass rounded-2xl p-4\">\n    <div class=\"rule-row\"><span class=\"suffix-pill\">5.1</span><span class=\"text-dark2\">Dùng để miêu tả</span></div>\n    <div class=\"text-sm text-soft mt-1\">Trả lời câu hỏi \"Nó làm sao? Nó như thế nào?\". Gồm 2 loại:</div>\n    <div class=\"ex-card mt-2\">Tính từ mô tả chung (không viết hoa): beautiful, nice, luxurious, terrible, small, ugly, short, comfortable.<br>Tính từ mô tả riêng (từ danh từ riêng, viết hoa): Chinese, Japanese, Vietnamese, American.</div>\n    <div class=\"rule-row mt-3\"><span class=\"suffix-pill\">5.2</span><span class=\"text-dark2\">Dùng để phân loại (tính từ giới hạn)</span></div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;margin-top:8px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:40%\">Tính từ số đếm (cardinal)</td><td style=\"padding:6px;color:var(--text-soft)\">one, two, three</td></tr>\n        <tr><td style=\"padding:6px\">Tính từ số thứ tự (ordinal)</td><td style=\"padding:6px;color:var(--text-soft)\">first, second, third</td></tr>\n        <tr><td style=\"padding:6px\">Tính từ chỉ định (demonstrative)</td><td style=\"padding:6px;color:var(--text-soft)\">this, that, these, those</td></tr>\n        <tr><td style=\"padding:6px\">Tính từ sở hữu (possessive)</td><td style=\"padding:6px;color:var(--text-soft)\">my, your, our, their, his, her, its</td></tr>\n        <tr><td style=\"padding:6px\">Tính từ nghi vấn (interrogative)</td><td style=\"padding:6px;color:var(--text-soft)\">what, which, whose</td></tr>\n        <tr><td style=\"padding:6px\">V-ing (gerund làm tính từ)</td><td style=\"padding:6px;color:var(--text-soft)\">amusing, depressing, disappointing, overwhelming, pleasing</td></tr>\n        <tr><td style=\"padding:6px\">V-ed/V3 (past participle)</td><td style=\"padding:6px;color:var(--text-soft)\">amused, depressed, disappointed, overwhelmed, pleased</td></tr>\n      </tbody>\n    </table>\n  </div>\n</details>\n\n<details class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#e07a5f,#f2a488);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">6</span> Cấu trúc ADJ + GIỚI TỪ thông dụng (157 cấu trúc — kèm phiên âm, phát âm, ví dụ song ngữ)\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2\" style=\"max-height:600px;overflow-y:auto\">\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">1. Be (im)possible (for sb) to do sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈpɒsəbl/</span> <button onclick=\"speakEnglish('possible')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có thể/không thể (cho ai) làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>It is possible for us to finish the project on time.</i><br><span style=\"color:var(--accent)\">→ Chúng tôi có thể hoàn thành dự án đúng hạn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">2. Be able to do sth = be capable of doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈeɪbl/</span> <button onclick=\"speakEnglish('able')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có thể, có khả năng làm gì đó</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is able to speak three languages fluently.</i><br><span style=\"color:var(--accent)\">→ Cô ấy có thể nói trôi chảy ba ngôn ngữ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">3. Be about to do sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈbaʊt/</span> <button onclick=\"speakEnglish('about')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">sắp sửa làm điều gì đó</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The train is about to leave the station.</i><br><span style=\"color:var(--accent)\">→ Chuyến tàu sắp sửa rời ga.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">4. Be absent from sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈæbsənt/</span> <button onclick=\"speakEnglish('absent')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">vắng mặt ở đâu</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He was absent from the meeting yesterday.</i><br><span style=\"color:var(--accent)\">→ Anh ấy đã vắng mặt trong cuộc họp hôm qua.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">5. Be absorbed in sth/doing sth = be engrossed in sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əbˈzɔːbd/</span> <button onclick=\"speakEnglish('absorbed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">miệt mài, say mê cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She was absorbed in reading her new novel.</i><br><span style=\"color:var(--accent)\">→ Cô ấy say mê đọc cuốn tiểu thuyết mới của mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">6. Be acceptable to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əkˈseptəbl/</span> <button onclick=\"speakEnglish('acceptable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có thể chấp nhận đối với ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This proposal is acceptable to the whole team.</i><br><span style=\"color:var(--accent)\">→ Đề xuất này được cả nhóm chấp nhận.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">7. Be accessible to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əkˈsesəbl/</span> <button onclick=\"speakEnglish('accessible')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có thể tiếp cận tới ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The park should be accessible to everyone, including the disabled.</i><br><span style=\"color:var(--accent)\">→ Công viên nên có thể tiếp cận được với mọi người, kể cả người khuyết tật.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">8. Be accountable for sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈkaʊntəbl/</span> <button onclick=\"speakEnglish('accountable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">chịu trách nhiệm giải trình cho việc gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Managers are accountable for their team's performance.</i><br><span style=\"color:var(--accent)\">→ Các quản lý phải chịu trách nhiệm giải trình về hiệu suất của nhóm mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">9. Be accurate in sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈækjərət/</span> <button onclick=\"speakEnglish('accurate')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">chính xác về cái gì đó</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Please be accurate in your calculations.</i><br><span style=\"color:var(--accent)\">→ Xin hãy chính xác trong các phép tính của bạn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">10. Be accustomed to sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈkʌstəmd/</span> <button onclick=\"speakEnglish('accustomed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">quen thuộc với cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I am accustomed to waking up early.</i><br><span style=\"color:var(--accent)\">→ Tôi đã quen với việc dậy sớm.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">11. Be acquainted with sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈkweɪntɪd/</span> <button onclick=\"speakEnglish('acquainted')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">quen biết với ai/hiểu biết, thông thạo cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I am acquainted with the new regulations.</i><br><span style=\"color:var(--accent)\">→ Tôi đã nắm rõ các quy định mới.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">12. Be addicted to sth/doing sth = be hooked on sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈdɪktɪd/</span> <button onclick=\"speakEnglish('addicted')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nghiện cái gì/làm gì đó</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is addicted to playing video games.</i><br><span style=\"color:var(--accent)\">→ Anh ấy nghiện chơi trò chơi điện tử.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">13. Be afraid of sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈfreɪd/</span> <button onclick=\"speakEnglish('afraid')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">sợ ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Many children are afraid of the dark.</i><br><span style=\"color:var(--accent)\">→ Nhiều đứa trẻ sợ bóng tối.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">14. Be agreeable to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈgriːəbl/</span> <button onclick=\"speakEnglish('agreeable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">sẵn sàng đồng ý việc gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The terms are agreeable to both parties.</i><br><span style=\"color:var(--accent)\">→ Các điều khoản được cả hai bên đồng ý.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">15. Be allergic to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈlɜːdʒɪk/</span> <button onclick=\"speakEnglish('allergic')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">ghét, không thích ai/dị ứng cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is allergic to shellfish.</i><br><span style=\"color:var(--accent)\">→ Cô ấy bị dị ứng với hải sản có vỏ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">16. Be amazed to do sth; Be amazed at/by sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈmeɪzd/</span> <button onclick=\"speakEnglish('amazed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">kinh ngạc khi làm gì; ngạc nhiên bởi ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I was amazed at how quickly she learned the dance.</i><br><span style=\"color:var(--accent)\">→ Tôi kinh ngạc trước tốc độ cô ấy học điệu nhảy.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">17. Be amused at/by sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈmjuːzd/</span> <button onclick=\"speakEnglish('amused')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">buồn cười/thích thú với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The audience was amused by his jokes.</i><br><span style=\"color:var(--accent)\">→ Khán giả thích thú với những câu đùa của anh ấy.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">18. Be angry with/at sb about/for sth; Be angry at/about/over sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈæŋgri/</span> <button onclick=\"speakEnglish('angry')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tức giận với ai về điều gì; tức giận việc gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She was angry with him for being late.</i><br><span style=\"color:var(--accent)\">→ Cô ấy tức giận với anh ta vì đến muộn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">19. Be annoyed with sb at/about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈnɔɪd/</span> <button onclick=\"speakEnglish('annoyed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">bực mình với ai về cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I was annoyed with my brother about the mess.</i><br><span style=\"color:var(--accent)\">→ Tôi bực mình với em trai vì sự bừa bộn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">20. Be appropriate for sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈprəʊpriət/</span> <button onclick=\"speakEnglish('appropriate')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">phù hợp, thích hợp với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This film isn't appropriate for young children.</i><br><span style=\"color:var(--accent)\">→ Bộ phim này không phù hợp với trẻ nhỏ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">21. Be ashamed of sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈʃeɪmd/</span> <button onclick=\"speakEnglish('ashamed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">xấu hổ về ai/điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He felt ashamed of his mistake.</i><br><span style=\"color:var(--accent)\">→ Anh ấy cảm thấy xấu hổ về lỗi lầm của mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">22. Be attentive to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈtentɪv/</span> <button onclick=\"speakEnglish('attentive')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tận tình, lưu tâm đến ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The waiter was very attentive to our needs.</i><br><span style=\"color:var(--accent)\">→ Người phục vụ rất tận tình với nhu cầu của chúng tôi.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">23. Be available for sth; Be available to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈveɪləbl/</span> <button onclick=\"speakEnglish('available')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có sẵn cho việc gì; có sẵn cho ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The manager is available for a meeting this afternoon.</i><br><span style=\"color:var(--accent)\">→ Giám đốc có thể sắp xếp cuộc họp chiều nay.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">24. Be aware of sth >< be unaware of sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈweər/</span> <button onclick=\"speakEnglish('aware')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nhận thức được điều gì đó >< không nhận thức được điều gì đó</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Are you aware of the new company policy?</i><br><span style=\"color:var(--accent)\">→ Bạn có biết về chính sách mới của công ty không?</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">25. Be away from sth/sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈweɪ/</span> <button onclick=\"speakEnglish('away')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tránh xa ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Keep the medicine away from children.</i><br><span style=\"color:var(--accent)\">→ Hãy để thuốc tránh xa tầm tay trẻ em.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">26. Be bad at sth; Be bad for sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/bæd/</span> <button onclick=\"speakEnglish('bad')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">dốt/kém cái gì; xấu/không tốt cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Smoking is bad for your health.</i><br><span style=\"color:var(--accent)\">→ Hút thuốc có hại cho sức khỏe của bạn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">27. Be based on sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/beɪst/</span> <button onclick=\"speakEnglish('based')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">dựa trên cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The movie is based on a true story.</i><br><span style=\"color:var(--accent)\">→ Bộ phim dựa trên một câu chuyện có thật.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">28. Be beneficial/advantageous to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˌbenɪˈfɪʃl/</span> <button onclick=\"speakEnglish('beneficial')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thuận lợi/có lợi cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Regular exercise is beneficial to your heart.</i><br><span style=\"color:var(--accent)\">→ Tập thể dục đều đặn có lợi cho tim của bạn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">29. Be bored with sth/doing sth = be fed up with sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/bɔːd/</span> <button onclick=\"speakEnglish('bored')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">chán ngấy, chán ngán cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I am bored with watching TV all day.</i><br><span style=\"color:var(--accent)\">→ Tôi chán việc xem TV cả ngày.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">30. Be busy with sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈbɪzi/</span> <button onclick=\"speakEnglish('busy')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">bận việc gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is busy with her final exams this week.</i><br><span style=\"color:var(--accent)\">→ Cô ấy bận rộn với kỳ thi cuối kỳ tuần này.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">31. Be careful of/with/about sth; Be careful about doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkeəfl/</span> <button onclick=\"speakEnglish('careful')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">cẩn thận về điều gì; cẩn thận khi làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Be careful with that glass vase.</i><br><span style=\"color:var(--accent)\">→ Hãy cẩn thận với chiếc bình thủy tinh đó.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">32. Be careless of sb to do sth; Be careless with/about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkeələs/</span> <button onclick=\"speakEnglish('careless')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">ai đó thật bất cẩn khi làm gì; bất cẩn với việc gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>It was careless of him to leave the door unlocked.</i><br><span style=\"color:var(--accent)\">→ Anh ta thật bất cẩn khi để cửa không khóa.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">33. Be central to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈsentrəl/</span> <button onclick=\"speakEnglish('central')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">là trung tâm, phần quan trọng của cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Trust is central to any relationship.</i><br><span style=\"color:var(--accent)\">→ Niềm tin là điều cốt lõi trong mọi mối quan hệ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">34. Be certain of/about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈsɜːtn/</span> <button onclick=\"speakEnglish('certain')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">chắc chắn về cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I am certain about my decision.</i><br><span style=\"color:var(--accent)\">→ Tôi chắc chắn về quyết định của mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">35. Be clear to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/klɪər/</span> <button onclick=\"speakEnglish('clear')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">rõ ràng với ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The instructions were clear to everyone.</i><br><span style=\"color:var(--accent)\">→ Hướng dẫn đã rõ ràng đối với mọi người.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">36. Be committed to doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kəˈmɪtɪd/</span> <button onclick=\"speakEnglish('committed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">cam kết làm cái gì đó</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The company is committed to reducing pollution.</i><br><span style=\"color:var(--accent)\">→ Công ty cam kết giảm thiểu ô nhiễm.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">37. Be compulsory for sb to do sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kəmˈpʌlsəri/</span> <button onclick=\"speakEnglish('compulsory')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">bắt buộc ai phải làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Wearing a helmet is compulsory for all riders.</i><br><span style=\"color:var(--accent)\">→ Đội mũ bảo hiểm là bắt buộc đối với mọi người đi xe.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">38. Be concerned about/for/over/at/by sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kənˈsɜːnd/</span> <button onclick=\"speakEnglish('concerned')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">quan tâm, lo ngại về điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Parents are concerned about their children's screen time.</i><br><span style=\"color:var(--accent)\">→ Phụ huynh lo ngại về thời gian con cái dùng thiết bị điện tử.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">39. Be confident of/in/about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkɒnfɪdənt/</span> <button onclick=\"speakEnglish('confident')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tự tin về điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is confident about passing the exam.</i><br><span style=\"color:var(--accent)\">→ Cô ấy tự tin về việc vượt qua kỳ thi.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">40. Be confused about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kənˈfjuːzd/</span> <button onclick=\"speakEnglish('confused')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">bối rối, lúng túng về cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm confused about which bus to take.</i><br><span style=\"color:var(--accent)\">→ Tôi đang bối rối không biết nên bắt xe buýt nào.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">41. Be conscious of sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkɒnʃəs/</span> <button onclick=\"speakEnglish('conscious')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có ý thức về cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is very conscious of her diet.</i><br><span style=\"color:var(--accent)\">→ Cô ấy rất có ý thức về chế độ ăn của mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">42. Be consistent with sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kənˈsɪstənt/</span> <button onclick=\"speakEnglish('consistent')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nhất quán, phù hợp với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>His actions are not consistent with his words.</i><br><span style=\"color:var(--accent)\">→ Hành động của anh ta không nhất quán với lời nói.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">43. Be content to do sth = be willing to do sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kənˈtent/</span> <button onclick=\"speakEnglish('content')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">sẵn lòng làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He was content to wait outside.</i><br><span style=\"color:var(--accent)\">→ Anh ấy sẵn lòng chờ đợi bên ngoài.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">44. Be content with sth = be satisfied with sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kənˈtent/</span> <button onclick=\"speakEnglish('content')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">hài lòng với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is content with her current job.</i><br><span style=\"color:var(--accent)\">→ Cô ấy hài lòng với công việc hiện tại.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">45. Be contrary to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkɒntrəri/</span> <button onclick=\"speakEnglish('contrary')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">trái ngược với điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>His behavior is contrary to company policy.</i><br><span style=\"color:var(--accent)\">→ Hành vi của anh ta trái ngược với chính sách công ty.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">46. Be convenient for sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kənˈviːniənt/</span> <button onclick=\"speakEnglish('convenient')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thuận tiện, tiện lợi cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Is Monday convenient for you?</i><br><span style=\"color:var(--accent)\">→ Thứ Hai có thuận tiện cho bạn không?</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">47. Be covered with sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkʌvəd/</span> <button onclick=\"speakEnglish('covered')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">được bao phủ bởi cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The hills were covered with snow.</i><br><span style=\"color:var(--accent)\">→ Những ngọn đồi phủ đầy tuyết.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">48. Be crazy about sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkreɪzi/</span> <button onclick=\"speakEnglish('crazy')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">say mê, yêu thích ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>My sister is crazy about K-pop.</i><br><span style=\"color:var(--accent)\">→ Em gái tôi rất mê nhạc K-pop.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">49. Be critical of sb/sth; Be critical to/for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkrɪtɪkl/</span> <button onclick=\"speakEnglish('critical')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">phê bình, chỉ trích ai/cái gì; cực kì quan trọng đối với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is often critical of his colleagues' work.</i><br><span style=\"color:var(--accent)\">→ Anh ta thường chỉ trích công việc của đồng nghiệp.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">50. Be crowded with sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkraʊdɪd/</span> <button onclick=\"speakEnglish('crowded')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">đông đúc, đầy ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The beach was crowded with tourists.</i><br><span style=\"color:var(--accent)\">→ Bãi biển đông nghịt khách du lịch.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">51. Be curious about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkjʊəriəs/</span> <button onclick=\"speakEnglish('curious')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tò mò về cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Children are naturally curious about the world.</i><br><span style=\"color:var(--accent)\">→ Trẻ em vốn dĩ tò mò về thế giới.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">52. Be dangerous for sb to do sth; Be dangerous to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈdeɪndʒərəs/</span> <button onclick=\"speakEnglish('dangerous')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nguy hiểm cho ai khi làm gì; nguy hiểm cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>It is dangerous for children to play near the river.</i><br><span style=\"color:var(--accent)\">→ Thật nguy hiểm khi trẻ em chơi gần sông.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">53. Be dedicated/devoted/committed to sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈdedɪkeɪtɪd/</span> <button onclick=\"speakEnglish('dedicated')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tận tụy, tận tâm với cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is dedicated to helping the poor.</i><br><span style=\"color:var(--accent)\">→ Cô ấy tận tâm giúp đỡ người nghèo.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">54. Be deficient in sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/dɪˈfɪʃnt/</span> <button onclick=\"speakEnglish('deficient')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thiếu hụt, không có đủ cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>His diet is deficient in vitamins.</i><br><span style=\"color:var(--accent)\">→ Chế độ ăn của anh ấy thiếu vitamin.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">55. Be delighted by/at/with/about sth; Be delighted for sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/dɪˈlaɪtɪd/</span> <button onclick=\"speakEnglish('delighted')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">vui sướng với điều gì/thứ gì; mừng cho ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>We were delighted with the results.</i><br><span style=\"color:var(--accent)\">→ Chúng tôi rất vui mừng với kết quả.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">56. Be dependent on/upon sb/sth = depend on sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/dɪˈpendənt/</span> <button onclick=\"speakEnglish('dependent')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">dựa dẫm vào ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Young children are dependent on their parents.</i><br><span style=\"color:var(--accent)\">→ Trẻ nhỏ phụ thuộc vào cha mẹ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">57. Be derived from sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/dɪˈraɪvd/</span> <button onclick=\"speakEnglish('derived')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có nguồn gốc từ cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The word 'democracy' is derived from Greek.</i><br><span style=\"color:var(--accent)\">→ Từ 'democracy' có nguồn gốc từ tiếng Hy Lạp.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">58. Be diagnosed with sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈdaɪəgnəʊzd/</span> <button onclick=\"speakEnglish('diagnosed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">bị chuẩn đoán mắc bệnh gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He was diagnosed with diabetes last year.</i><br><span style=\"color:var(--accent)\">→ Anh ấy được chẩn đoán mắc bệnh tiểu đường năm ngoái.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">59. Be different from sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈdɪfrənt/</span> <button onclick=\"speakEnglish('different')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">khác với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This city is very different from my hometown.</i><br><span style=\"color:var(--accent)\">→ Thành phố này rất khác với quê tôi.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">60. Be difficult for sb to do sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈdɪfɪkəlt/</span> <button onclick=\"speakEnglish('difficult')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">khó khăn cho ai để làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>It was difficult for her to accept the news.</i><br><span style=\"color:var(--accent)\">→ Thật khó khăn để cô ấy chấp nhận tin đó.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">61. Be disappointed at/about/by/in/with sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˌdɪsəˈpɔɪntɪd/</span> <button onclick=\"speakEnglish('disappointed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thất vọng về điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I was disappointed with my exam results.</i><br><span style=\"color:var(--accent)\">→ Tôi thất vọng về kết quả thi của mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">62. Be divided into sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/dɪˈvaɪdɪd/</span> <button onclick=\"speakEnglish('divided')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">được chia thành cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The book is divided into ten chapters.</i><br><span style=\"color:var(--accent)\">→ Cuốn sách được chia thành mười chương.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">63. Be done with sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/dʌn/</span> <button onclick=\"speakEnglish('done')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">làm xong, hoàn thành cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm done with my homework.</i><br><span style=\"color:var(--accent)\">→ Tôi đã làm xong bài tập về nhà.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">64. Be doubtful/dubious about sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈdaʊtfl/</span> <button onclick=\"speakEnglish('doubtful')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nghi ngờ, không chắc chắn về cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm doubtful about his ability to finish on time.</i><br><span style=\"color:var(--accent)\">→ Tôi nghi ngờ khả năng anh ấy hoàn thành đúng hạn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">65. Be eager for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈiːgər/</span> <button onclick=\"speakEnglish('eager')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">háo hức, hăm hở cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The students are eager for the summer holidays.</i><br><span style=\"color:var(--accent)\">→ Học sinh háo hức chờ kỳ nghỉ hè.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">66. Be efficient at/in sth; Be efficient in doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪˈfɪʃnt/</span> <button onclick=\"speakEnglish('efficient')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có năng lực, khả năng với cái gì; có khả năng làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is efficient at managing her time.</i><br><span style=\"color:var(--accent)\">→ Cô ấy rất giỏi trong việc quản lý thời gian.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">67. Be eligible for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈelɪdʒəbl/</span> <button onclick=\"speakEnglish('eligible')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">đủ tư cách/điều kiện cho cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>You must be 18 to be eligible for a driving license.</i><br><span style=\"color:var(--accent)\">→ Bạn phải đủ 18 tuổi để đủ điều kiện thi bằng lái xe.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">68. Be engaged in/on/with sth; Be engaged to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪnˈgeɪdʒd/</span> <button onclick=\"speakEnglish('engaged')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tất bật, mải mê với cái gì; đính hôn với ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is engaged in a research project.</i><br><span style=\"color:var(--accent)\">→ Cô ấy đang bận rộn với một dự án nghiên cứu.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">69. Be enthusiastic about sb/sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪnˌθjuːziˈæstɪk/</span> <button onclick=\"speakEnglish('enthusiastic')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nhiệt tình, đam mê với ai/cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is enthusiastic about learning new languages.</i><br><span style=\"color:var(--accent)\">→ Anh ấy rất nhiệt tình học ngôn ngữ mới.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">70. Be equal to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈiːkwəl/</span> <button onclick=\"speakEnglish('equal')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">ngang bằng với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>One kilometer is equal to 1000 meters.</i><br><span style=\"color:var(--accent)\">→ Một ki-lô-mét bằng 1000 mét.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">71. Be excited about/at/by/for sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪkˈsaɪtɪd/</span> <button onclick=\"speakEnglish('excited')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">hào hứng với cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>We are excited about the upcoming trip.</i><br><span style=\"color:var(--accent)\">→ Chúng tôi rất hào hứng về chuyến đi sắp tới.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">72. Be experienced in sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪkˈspɪəriənst/</span> <button onclick=\"speakEnglish('experienced')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có kinh nghiệm về cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is experienced in customer service.</i><br><span style=\"color:var(--accent)\">→ Cô ấy có kinh nghiệm trong dịch vụ khách hàng.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">73. Be expert at/in/on sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈekspɜːt/</span> <button onclick=\"speakEnglish('expert')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thành thạo, thông thạo, lão luyện cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is an expert at fixing computers, so he is expert in this field.</i><br><span style=\"color:var(--accent)\">→ Anh ấy rất giỏi sửa máy tính, thành thạo trong lĩnh vực này.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">74. Be exposed to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪkˈspəʊzd/</span> <button onclick=\"speakEnglish('exposed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tiếp xúc với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Workers are exposed to loud noise every day.</i><br><span style=\"color:var(--accent)\">→ Công nhân tiếp xúc với tiếng ồn lớn mỗi ngày.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">75. Be familiar with sth; Be familiar to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/fəˈmɪliər/</span> <button onclick=\"speakEnglish('familiar')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">quen thuộc cái gì; quen thuộc, thân thuộc với ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I am familiar with this software.</i><br><span style=\"color:var(--accent)\">→ Tôi đã quen thuộc với phần mềm này.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">76. Be famous/renowned/well-known for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈfeɪməs/</span> <button onclick=\"speakEnglish('famous')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nổi tiếng vì điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Vietnam is famous for its beautiful beaches.</i><br><span style=\"color:var(--accent)\">→ Việt Nam nổi tiếng với những bãi biển đẹp.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">77. Be far from sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/fɑːr/</span> <button onclick=\"speakEnglish('far')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">xa ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>My house is far from the city center.</i><br><span style=\"color:var(--accent)\">→ Nhà tôi ở xa trung tâm thành phố.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">78. Be favorable to/for sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈfeɪvərəbl/</span> <button onclick=\"speakEnglish('favorable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thuận lợi/có lợi cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The weather is favorable for a picnic today.</i><br><span style=\"color:var(--accent)\">→ Thời tiết hôm nay thuận lợi cho một buổi dã ngoại.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">79. Be fed up with sth/doing sth = be bored with/of sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˌfed ˈʌp/</span> <button onclick=\"speakEnglish('fed up')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">chán nản với cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm fed up with the traffic jams every morning.</i><br><span style=\"color:var(--accent)\">→ Tôi chán ngán cảnh tắc đường mỗi sáng.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">80. Be fit for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/fɪt/</span> <button onclick=\"speakEnglish('fit')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">phù hợp/đủ sức khỏe cho việc gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This water isn't fit for drinking.</i><br><span style=\"color:var(--accent)\">→ Nước này không phù hợp để uống.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">81. Be fluent in sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈfluːənt/</span> <button onclick=\"speakEnglish('fluent')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thông thạo, thành thạo cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is fluent in Spanish and French.</i><br><span style=\"color:var(--accent)\">→ Cô ấy thông thạo tiếng Tây Ban Nha và tiếng Pháp.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">82. Be fond of = be keen on = be interested in sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/fɒnd/</span> <button onclick=\"speakEnglish('fond')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thích, say mê điều gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is fond of classical music.</i><br><span style=\"color:var(--accent)\">→ Anh ấy rất thích nhạc cổ điển.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">83. Be free for sth; Be free to/for sb; Be free of/from sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/friː/</span> <button onclick=\"speakEnglish('free')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">rảnh cho việc gì; miễn phí với ai; thoát khỏi cái gì/không có cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Entry is free for children under five.</i><br><span style=\"color:var(--accent)\">→ Vé vào cửa miễn phí cho trẻ em dưới 5 tuổi.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">84. Be full of sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/fʊl/</span> <button onclick=\"speakEnglish('full')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">chứa đầy thứ gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The basket is full of fresh fruit.</i><br><span style=\"color:var(--accent)\">→ Cái giỏ đầy trái cây tươi.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">85. Be gentle with sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈdʒentl/</span> <button onclick=\"speakEnglish('gentle')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">dịu dàng, nhẹ nhàng với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Please be gentle with the puppy.</i><br><span style=\"color:var(--accent)\">→ Xin hãy nhẹ nhàng với chú chó con.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">86. Be glad about sth; Be glad to do sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/glæd/</span> <button onclick=\"speakEnglish('glad')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">vui về điều gì; vui khi làm gì đó</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm glad about your success.</i><br><span style=\"color:var(--accent)\">→ Tôi rất vui về thành công của bạn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">87. Be good/clever at sth/doing sth >< be bad at sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/gʊd/</span> <button onclick=\"speakEnglish('good')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">giỏi về cái gì/làm gì >< kém về cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is good at solving math problems.</i><br><span style=\"color:var(--accent)\">→ Cô ấy giỏi giải các bài toán.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">88. Be grateful to sb for sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈgreɪtfl/</span> <button onclick=\"speakEnglish('grateful')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">biết ơn ai vì điều gì/vì đã làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I am grateful to my teacher for her guidance.</i><br><span style=\"color:var(--accent)\">→ Tôi biết ơn giáo viên của mình vì sự hướng dẫn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">89. Be greedy for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈgriːdi/</span> <button onclick=\"speakEnglish('greedy')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tham lam, hám cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Some companies are greedy for profit.</i><br><span style=\"color:var(--accent)\">→ Một số công ty tham lam lợi nhuận.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">90. Be guilty of sth >< be innocent of sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈgɪlti/</span> <button onclick=\"speakEnglish('guilty')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có tội gì >< vô tội</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He was found guilty of theft.</i><br><span style=\"color:var(--accent)\">→ Anh ta bị kết tội trộm cắp.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">91. Be harmful to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈhɑːmfl/</span> <button onclick=\"speakEnglish('harmful')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có hại cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>UV rays can be harmful to your skin.</i><br><span style=\"color:var(--accent)\">→ Tia UV có thể có hại cho da của bạn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">92. Be helpful/useful for sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈhelpfl/</span> <button onclick=\"speakEnglish('helpful')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">hữu ích, giúp ích cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This app is very helpful for learning vocabulary.</i><br><span style=\"color:var(--accent)\">→ Ứng dụng này rất hữu ích để học từ vựng.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">93. Be hooked on sth = be addicted to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/hʊkt/</span> <button onclick=\"speakEnglish('hooked')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nghiện cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm hooked on this new TV series.</i><br><span style=\"color:var(--accent)\">→ Tôi đang nghiện bộ phim truyền hình mới này.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">94. Be hopeful about sth = be optimistic about sth; Be hopeful of doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈhəʊpfl/</span> <button onclick=\"speakEnglish('hopeful')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">hi vọng, lạc quan về điều gì; hi vọng, lạc quan về việc làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>We are hopeful about the future of the company.</i><br><span style=\"color:var(--accent)\">→ Chúng tôi lạc quan về tương lai của công ty.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">95. Be identical to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/aɪˈdentɪkl/</span> <button onclick=\"speakEnglish('identical')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">giống hệt với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The twins look identical to each other.</i><br><span style=\"color:var(--accent)\">→ Cặp sinh đôi trông giống hệt nhau.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">96. Be important to/for sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪmˈpɔːtnt/</span> <button onclick=\"speakEnglish('important')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">quan trọng với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Honesty is important to every relationship.</i><br><span style=\"color:var(--accent)\">→ Sự trung thực rất quan trọng đối với mọi mối quan hệ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">97. Be impressed with/by/at sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪmˈprest/</span> <button onclick=\"speakEnglish('impressed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">ấn tượng với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I was impressed by her presentation.</i><br><span style=\"color:var(--accent)\">→ Tôi ấn tượng với bài thuyết trình của cô ấy.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">98. Be independent of/from sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˌɪndɪˈpendənt/</span> <button onclick=\"speakEnglish('independent')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">độc lập với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She wants to be financially independent of her parents.</i><br><span style=\"color:var(--accent)\">→ Cô ấy muốn độc lập tài chính khỏi cha mẹ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">99. Be indifferent to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪnˈdɪfrənt/</span> <button onclick=\"speakEnglish('indifferent')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thờ ơ với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He seems indifferent to other people's opinions.</i><br><span style=\"color:var(--accent)\">→ Anh ta có vẻ thờ ơ với ý kiến của người khác.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">100. Be inferior to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪnˈfɪəriər/</span> <button onclick=\"speakEnglish('inferior')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thua thém, thấp kém hơn ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This model is inferior to the newer version.</i><br><span style=\"color:var(--accent)\">→ Mẫu này kém hơn so với phiên bản mới.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">101. Be involved in sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ɪnˈvɒlvd/</span> <button onclick=\"speakEnglish('involved')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">liên quan, dính díu đến cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is deeply involved in local charity work.</i><br><span style=\"color:var(--accent)\">→ Cô ấy tham gia sâu vào công tác từ thiện địa phương.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">102. Be jealous/envious of sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈdʒeləs/</span> <button onclick=\"speakEnglish('jealous')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">ghen tị với ai/điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He was jealous of his friend's new car.</i><br><span style=\"color:var(--accent)\">→ Anh ấy ghen tị với chiếc xe mới của bạn mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">103. Be kind to sb/sth; Be kind of sb to do sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kaɪnd/</span> <button onclick=\"speakEnglish('kind')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tốt với ai/cái gì; ai đó thật tốt khi làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>It was kind of you to help me.</i><br><span style=\"color:var(--accent)\">→ Bạn thật tốt bụng khi giúp tôi.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">104. Be late for sth >< be on time/in time</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/leɪt/</span> <button onclick=\"speakEnglish('late')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">bị muộn, trễ cái gì >< đúng giờ/kịp giờ</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He was late for his flight.</i><br><span style=\"color:var(--accent)\">→ Anh ấy bị trễ chuyến bay.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">105. Be liable for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈlaɪəbl/</span> <button onclick=\"speakEnglish('liable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có trách nhiệm (về pháp lý) cho cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The company is liable for any damage caused.</i><br><span style=\"color:var(--accent)\">→ Công ty chịu trách nhiệm pháp lý cho mọi thiệt hại gây ra.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">106. Be loyal/faithful to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈlɔɪəl/</span> <button onclick=\"speakEnglish('loyal')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">trung thành, chung thủy với ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>A good employee should be loyal to the company.</i><br><span style=\"color:var(--accent)\">→ Một nhân viên tốt nên trung thành với công ty.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">107. Be mad about/on/for sb/sth; Be mad at/with sb for doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/mæd/</span> <button onclick=\"speakEnglish('mad')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">yêu thích ai/say mê ai/cái gì; tức giận ai vì đã làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is mad about horror movies.</i><br><span style=\"color:var(--accent)\">→ Cô ấy rất mê phim kinh dị.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">108. Be necessary for sth/sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈnesəsəri/</span> <button onclick=\"speakEnglish('necessary')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">cần thiết cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>A passport is necessary for international travel.</i><br><span style=\"color:var(--accent)\">→ Hộ chiếu là cần thiết cho việc đi du lịch quốc tế.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">109. Be next to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/nekst/</span> <button onclick=\"speakEnglish('next')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">bên cạnh ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The bank is next to the supermarket.</i><br><span style=\"color:var(--accent)\">→ Ngân hàng nằm bên cạnh siêu thị.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">110. Be open to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈəʊpən/</span> <button onclick=\"speakEnglish('open')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">rộng mở, cởi mở với ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is always open to new ideas.</i><br><span style=\"color:var(--accent)\">→ Cô ấy luôn cởi mở với những ý tưởng mới.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">111. Be opposed to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈpəʊzd/</span> <button onclick=\"speakEnglish('opposed')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">phản đối ai/điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Many residents are opposed to the new highway plan.</i><br><span style=\"color:var(--accent)\">→ Nhiều cư dân phản đối kế hoạch xây đường cao tốc mới.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">112. Be optimistic about sth >< be pessimistic about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˌɒptɪˈmɪstɪk/</span> <button onclick=\"speakEnglish('optimistic')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">lạc quan về cái gì >< bi quan về cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is optimistic about his career.</i><br><span style=\"color:var(--accent)\">→ Anh ấy lạc quan về sự nghiệp của mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">113. Be particular about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/pəˈtɪkjələr/</span> <button onclick=\"speakEnglish('particular')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">kĩ tính về việc gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is particular about the food she eats.</i><br><span style=\"color:var(--accent)\">→ Cô ấy rất kỹ tính về đồ ăn mình dùng.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">114. Be passionate about sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈpæʃənət/</span> <button onclick=\"speakEnglish('passionate')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">đam mê cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is passionate about photography.</i><br><span style=\"color:var(--accent)\">→ Anh ấy đam mê nhiếp ảnh.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">115. Be patient with sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈpeɪʃnt/</span> <button onclick=\"speakEnglish('patient')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">kiên nhẫn với ai/điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Teachers need to be patient with young children.</i><br><span style=\"color:var(--accent)\">→ Giáo viên cần kiên nhẫn với trẻ nhỏ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">116. Be perfect for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈpɜːfɪkt/</span> <button onclick=\"speakEnglish('perfect')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">hoàn hảo, lý tưởng cho cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This weather is perfect for a picnic.</i><br><span style=\"color:var(--accent)\">→ Thời tiết này lý tưởng cho một buổi dã ngoại.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">117. Be pleasant to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈpleznt/</span> <button onclick=\"speakEnglish('pleasant')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">lịch sự và thân thiện với ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The staff were very pleasant to us.</i><br><span style=\"color:var(--accent)\">→ Nhân viên rất lịch sự và thân thiện với chúng tôi.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">118. Be pleased with/at/about sth; Be pleased for sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/pliːzd/</span> <button onclick=\"speakEnglish('pleased')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">cảm thấy vui về điều gì; cảm thấy vui/mừng cho ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm pleased with my new job.</i><br><span style=\"color:var(--accent)\">→ Tôi hài lòng với công việc mới của mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">119. Be popular with sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈpɒpjələr/</span> <button onclick=\"speakEnglish('popular')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">được yêu thích bởi ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This singer is very popular with teenagers.</i><br><span style=\"color:var(--accent)\">→ Ca sĩ này rất được yêu thích bởi thanh thiếu niên.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">120. Be preferable to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈprefrəbl/</span> <button onclick=\"speakEnglish('preferable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thích hơn, được ưa hơn; hợp hơn</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>A quiet evening at home is preferable to a noisy party.</i><br><span style=\"color:var(--accent)\">→ Một buổi tối yên tĩnh ở nhà thì tốt hơn một bữa tiệc ồn ào.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">121. Be present at sth; Be present in sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈpreznt/</span> <button onclick=\"speakEnglish('present')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có mặt ở đâu; tồn tại ở trong đâu</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>All employees must be present at the meeting.</i><br><span style=\"color:var(--accent)\">→ Tất cả nhân viên phải có mặt tại cuộc họp.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">122. Be proficient in/at sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/prəˈfɪʃnt/</span> <button onclick=\"speakEnglish('proficient')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thạo làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is proficient in using Excel.</i><br><span style=\"color:var(--accent)\">→ Cô ấy thành thạo việc sử dụng Excel.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">123. Be proud of sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/praʊd/</span> <button onclick=\"speakEnglish('proud')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">tự hào về ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Parents are proud of their children's achievements.</i><br><span style=\"color:var(--accent)\">→ Cha mẹ tự hào về thành tích của con cái.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">124. Be qualified for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈkwɒlɪfaɪd/</span> <button onclick=\"speakEnglish('qualified')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">đủ tư cách, đủ khả năng, đủ điều kiện cho việc gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is qualified for the manager position.</i><br><span style=\"color:var(--accent)\">→ Anh ấy đủ điều kiện cho vị trí quản lý.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">125. Be quick at sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/kwɪk/</span> <button onclick=\"speakEnglish('quick')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nhanh nhẹn, nhạy bén về cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is quick at learning new skills.</i><br><span style=\"color:var(--accent)\">→ Cô ấy học kỹ năng mới rất nhanh.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">126. Be ready for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈredi/</span> <button onclick=\"speakEnglish('ready')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">sẵn sàng cho điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Are you ready for the exam tomorrow?</i><br><span style=\"color:var(--accent)\">→ Bạn đã sẵn sàng cho kỳ thi ngày mai chưa?</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">127. Be related to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/rɪˈleɪtɪd/</span> <button onclick=\"speakEnglish('related')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có quan hệ với ai/liên quan tới cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This issue is related to the budget cuts.</i><br><span style=\"color:var(--accent)\">→ Vấn đề này liên quan đến việc cắt giảm ngân sách.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">128. Be resistant to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/rɪˈzɪstənt/</span> <button onclick=\"speakEnglish('resistant')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">chịu đựng, chống chịu được với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This material is resistant to fire.</i><br><span style=\"color:var(--accent)\">→ Vật liệu này chống chịu được lửa.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">129. Be responsible for sth/doing sth = be in charge of sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/rɪˈspɒnsəbl/</span> <button onclick=\"speakEnglish('responsible')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">chịu trách nghiệm với cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is responsible for the whole project.</i><br><span style=\"color:var(--accent)\">→ Cô ấy chịu trách nhiệm cho toàn bộ dự án.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">130. Be rich in sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/rɪtʃ/</span> <button onclick=\"speakEnglish('rich')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">giàu, dồi dào cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Oranges are rich in vitamin C.</i><br><span style=\"color:var(--accent)\">→ Cam giàu vitamin C.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">131. Be rude to sb >< be polite to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ruːd/</span> <button onclick=\"speakEnglish('rude')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thô lỗ, cộc cằn với ai >< lịch sự, lễ phép với ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>It's rude to interrupt someone while they're talking.</i><br><span style=\"color:var(--accent)\">→ Thật thô lỗ khi ngắt lời người khác đang nói.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">132. Be sad at/about/for sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/sæd/</span> <button onclick=\"speakEnglish('sad')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">buồn về điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I feel sad about leaving my hometown.</i><br><span style=\"color:var(--accent)\">→ Tôi cảm thấy buồn khi phải rời quê hương.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">133. Be safe from sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/seɪf/</span> <button onclick=\"speakEnglish('safe')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">an toàn trước cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This shelter keeps people safe from storms.</i><br><span style=\"color:var(--accent)\">→ Nơi trú ẩn này giữ an toàn cho mọi người trước bão.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">134. Be satisfied with sb/sth >< be dissatisfied with sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈsætɪsfaɪd/</span> <button onclick=\"speakEnglish('satisfied')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">hài lòng với ai/điều gì >< không hài lòng với ai/điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The customer was satisfied with the service.</i><br><span style=\"color:var(--accent)\">→ Khách hàng đã hài lòng với dịch vụ.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">135. Be scared/terrified/frightened of sb/sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/skeəd/</span> <button onclick=\"speakEnglish('scared')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">sợ hãi, lo sợ ai/cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>My little sister is scared of thunderstorms.</i><br><span style=\"color:var(--accent)\">→ Em gái nhỏ của tôi sợ giông bão.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">136. Be sensitive to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈsensətɪv/</span> <button onclick=\"speakEnglish('sensitive')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nhạy cảm với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Her skin is sensitive to sunlight.</i><br><span style=\"color:var(--accent)\">→ Da của cô ấy nhạy cảm với ánh nắng.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">137. Be serious about sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈsɪəriəs/</span> <button onclick=\"speakEnglish('serious')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nghiêm túc về điều gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is serious about improving his English.</i><br><span style=\"color:var(--accent)\">→ Anh ấy nghiêm túc trong việc cải thiện tiếng Anh.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">138. Be shocked/surprised/astonished at/by sb/sth = be amazed at sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ʃɒkt/</span> <button onclick=\"speakEnglish('shocked')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">sửng sốt, bất ngờ, ngạc nhiên về ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>We were shocked by the sudden news.</i><br><span style=\"color:var(--accent)\">→ Chúng tôi sửng sốt trước tin tức bất ngờ đó.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">139. Be short of</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ʃɔːt/</span> <button onclick=\"speakEnglish('short')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thiếu cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The company is short of skilled workers.</i><br><span style=\"color:var(--accent)\">→ Công ty đang thiếu lao động lành nghề.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">140. Be sick of sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/sɪk/</span> <button onclick=\"speakEnglish('sick')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">ngao ngán ai/thứ gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm sick of eating instant noodles every day.</i><br><span style=\"color:var(--accent)\">→ Tôi ngán ăn mì ăn liền mỗi ngày.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">141. Be similar to sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈsɪmələr/</span> <button onclick=\"speakEnglish('similar')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">giống, tương tự với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Her handwriting is similar to her mother's.</i><br><span style=\"color:var(--accent)\">→ Chữ viết tay của cô ấy giống mẹ mình.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">142. Be skillful at sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈskɪlfl/</span> <button onclick=\"speakEnglish('skillful')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">khéo léo, điêu luyện việc gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He is skillful at negotiating deals.</i><br><span style=\"color:var(--accent)\">→ Anh ấy rất khéo léo trong việc đàm phán.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">143. Be sorry for/about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈsɒri/</span> <button onclick=\"speakEnglish('sorry')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">lấy làm tiếc về điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm sorry for the inconvenience.</i><br><span style=\"color:var(--accent)\">→ Tôi xin lỗi vì sự bất tiện này.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">144. Be successful in sth/doing sth = succeed in sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/səkˈsesfl/</span> <button onclick=\"speakEnglish('successful')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thành công với cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She was successful in starting her own business.</i><br><span style=\"color:var(--accent)\">→ Cô ấy đã thành công trong việc khởi nghiệp.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">145. Be suitable for sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈsuːtəbl/</span> <button onclick=\"speakEnglish('suitable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">thích hợp, phù hợp cho ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This job is suitable for fresh graduates.</i><br><span style=\"color:var(--accent)\">→ Công việc này phù hợp cho sinh viên mới ra trường.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">146. Be superior to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/suːˈpɪəriər/</span> <button onclick=\"speakEnglish('superior')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">vượt trội, tốt hơn ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This product is superior to its competitors.</i><br><span style=\"color:var(--accent)\">→ Sản phẩm này vượt trội hơn các đối thủ cạnh tranh.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">147. Be surprised at/by sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/səˈpraɪzd/</span> <button onclick=\"speakEnglish('surprised')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">ngạc nhiên với cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I was surprised at how fast he finished.</i><br><span style=\"color:var(--accent)\">→ Tôi ngạc nhiên vì anh ấy hoàn thành nhanh như vậy.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">148. Be suspicious of/about sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/səˈspɪʃəs/</span> <button onclick=\"speakEnglish('suspicious')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">nghi ngờ về ai/điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>The police were suspicious of his story.</i><br><span style=\"color:var(--accent)\">→ Cảnh sát nghi ngờ câu chuyện của anh ta.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">149. Be tired from sth/doing sth; Be tired of sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈtaɪəd/</span> <button onclick=\"speakEnglish('tired')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">mệt mỏi sau khi đi đâu/làm gì; mệt mỏi với cái gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm tired from working all day.</i><br><span style=\"color:var(--accent)\">→ Tôi mệt mỏi sau cả ngày làm việc.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">150. Be tolerant of/towards sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈtɒlərənt/</span> <button onclick=\"speakEnglish('tolerant')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">bao dung với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Good teachers are tolerant of students' mistakes.</i><br><span style=\"color:var(--accent)\">→ Giáo viên tốt bao dung với lỗi lầm của học sinh.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">151. Be typical of sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈtɪpɪkl/</span> <button onclick=\"speakEnglish('typical')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">điển hình, tiêu biểu của ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>This kind of behavior is typical of teenagers.</i><br><span style=\"color:var(--accent)\">→ Loại hành vi này điển hình ở tuổi thanh thiếu niên.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">152. Be uneasy/anxious/worried about sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈwʌrid/</span> <button onclick=\"speakEnglish('worried')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">không thoải mái, lo lắng về cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>She is worried about her upcoming exams.</i><br><span style=\"color:var(--accent)\">→ Cô ấy lo lắng về kỳ thi sắp tới.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">153. Be upset about/at/over sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ʌpˈset/</span> <button onclick=\"speakEnglish('upset')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">buồn, không vui về điều gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>He was upset about losing the match.</i><br><span style=\"color:var(--accent)\">→ Anh ấy buồn vì thua trận đấu.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">154. Be used/accustomed to sth/doing sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/juːst/</span> <button onclick=\"speakEnglish('used')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">quen với việc gì/làm gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>I'm used to living in a big city.</i><br><span style=\"color:var(--accent)\">→ Tôi đã quen với việc sống ở thành phố lớn.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">155. Be vulnerable to sb/sth = be susceptible to sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/ˈvʌlnərəbl/</span> <button onclick=\"speakEnglish('vulnerable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">dễ bị tổn thương với, bởi ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Old people are more vulnerable to the flu.</i><br><span style=\"color:var(--accent)\">→ Người già dễ bị tổn thương hơn bởi bệnh cúm.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">156. Be wrong with sb/sth</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/rɒŋ/</span> <button onclick=\"speakEnglish('wrong')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">có vấn đề với ai/cái gì</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>There's something wrong with my laptop.</i><br><span style=\"color:var(--accent)\">→ Có gì đó không ổn với laptop của tôi.</span></div>\n</div>\n<div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\">\n<div style=\"font-weight:700;color:var(--dark2,#333)\">157. Be obedient to sb</div>\n<div class=\"mt-1\"><span style=\"color:var(--accent);font-size:12px\">/əˈbiːdiənt/</span> <button onclick=\"speakEnglish('obedient')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button></div>\n<div class=\"mt-1\" style=\"font-size:13px\">vâng lời ai</div>\n<div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\"><i>Children are taught to be obedient to their parents.</i><br><span style=\"color:var(--accent)\">→ Trẻ em được dạy phải vâng lời cha mẹ.</span></div>\n</div>\n\n  </div>\n</details>\n";
const ADJ_PHAN1_Q = [{"id": "adjerr_p1_1", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "We had an ", "B": "amazingly", "C": " experience during our trip to Japan.", "D": ""}, "active_letters": ["A", "B", "C"], "ans": 1, "correction": "amazing", "vi": "Chúng tôi đã có một trải nghiệm tuyệt vời trong chuyến đi Nhật Bản.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>amazing</u>\"</div><div class=\"ex-card mb-2\">We had an <u>amazing</u> experience during our trip to Japan.<br><span style=\"color:var(--accent);font-size:13px\">Chúng tôi đã có một trải nghiệm tuyệt vời trong chuyến đi Nhật Bản.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Cần TÍNH TỪ đứng trước danh từ \"experience\" để bổ nghĩa, không dùng trạng từ.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"amazingly\" là trạng từ (bổ nghĩa cho động từ/tính từ), không thể đứng trước danh từ \"experience\" → phải dùng tính từ \"amazing\".</div>"}, {"id": "adjerr_p1_2", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "She wore ", "B": "a dress beautiful", "C": " to the party last night.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "a beautiful dress", "vi": "Cô ấy đã mặc một chiếc váy đẹp đến bữa tiệc tối qua.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>a beautiful dress</u>\"</div><div class=\"ex-card mb-2\">She wore <u>a beautiful dress</u> to the party last night.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy đã mặc một chiếc váy đẹp đến bữa tiệc tối qua.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Tính từ mô tả thường đứng TRƯỚC danh từ mà nó bổ nghĩa, không đứng sau.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"beautiful\" phải đứng trước \"dress\" (a beautiful dress), không đứng sau danh từ trong câu này.</div>"}, {"id": "adjerr_p1_3", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "She found the lecture ", "B": "interesting", "C": " and decided to do more research on the topic.", "D": ""}, "active_letters": ["A", "B", "C"], "ans": -1, "correction": "", "vi": "Cô ấy thấy bài giảng thú vị và quyết định tìm hiểu thêm về chủ đề đó.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Câu này không có lỗi sai (câu đúng ngữ pháp)</div><div class=\"ex-card mb-2\">She found the lecture interesting and decided to do more research on the topic.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy thấy bài giảng thú vị và quyết định tìm hiểu thêm về chủ đề đó.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Câu này ĐÚNG ngữ pháp — không có lỗi sai.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Đây là ví dụ chuẩn cho cấu trúc \"find + O + Adj\" (tính từ đứng sau tân ngữ của động từ tri giác/nhận thức \"find\"): \"found the lecture interesting\" là hoàn toàn chính xác.</div>"}, {"id": "adjerr_p1_4", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The movie was so ", "B": "bored", "C": " that I almost fell asleep.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "boring", "vi": "Bộ phim nhàm chán đến mức tôi suýt ngủ gật.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>boring</u>\"</div><div class=\"ex-card mb-2\">The movie was so <u>boring</u> that I almost fell asleep.<br><span style=\"color:var(--accent);font-size:13px\">Bộ phim nhàm chán đến mức tôi suýt ngủ gật.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Vật/việc GÂY RA cảm giác → dùng tính từ đuôi -ing; người CẢM THẤY → dùng đuôi -ed.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"the movie\" là vật gây ra cảm giác chán, nên phải dùng \"boring\", không dùng \"bored\" (chỉ cảm xúc của người).</div>"}, {"id": "adjerr_p1_5", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "They live in a spacious modern square ", "B": "wooden white", "C": " family house in the countryside.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "white wooden", "vi": "Họ sống trong một ngôi nhà gia đình rộng rãi, hiện đại, hình vuông, màu trắng, bằng gỗ ở vùng quê.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>white wooden</u>\"</div><div class=\"ex-card mb-2\">They live in a spacious modern square <u>white wooden</u> family house in the countryside.<br><span style=\"color:var(--accent);font-size:13px\">Họ sống trong một ngôi nhà gia đình rộng rãi, hiện đại, hình vuông, màu trắng, bằng gỗ ở vùng quê.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Trật tự tính từ chuẩn OSASCOMP: Opinion-Size-Age-Shape-Color-Origin-Material-Purpose.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Theo thứ tự: spacious(Opinion) modern(Age) square(Shape) white(Color) wooden(Material) family(Purpose) — Color phải đứng TRƯỚC Material, nên \"wooden white\" bị sai thứ tự, phải sửa thành \"white wooden\".</div>"}, {"id": "adjerr_p1_6", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "She wore a beautiful old small round silver Italian ", "B": "necklace", "C": " to the party.", "D": ""}, "active_letters": ["A"], "ans": -1, "correction": "beautiful small old round Italian silver necklace", "vi": "Cô ấy đeo một chiếc vòng cổ đẹp, nhỏ, cũ, tròn, bằng bạc của Ý đến bữa tiệc.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Câu này không có lỗi sai (câu đúng ngữ pháp)</div><div class=\"ex-card mb-2\">She wore a beautiful old small round silver Italian necklace to the party.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy đeo một chiếc vòng cổ đẹp, nhỏ, cũ, tròn, bằng bạc của Ý đến bữa tiệc.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Trật tự chuẩn: Opinion-Size-Age-Shape-Color-Origin-Material-Purpose.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Câu gốc sắp xếp \"old small\" (Age trước Size — sai, phải là Size trước Age: \"small old\") và \"silver Italian\" (Material trước Origin — sai, phải là Origin trước Material: \"Italian silver\"). Thứ tự đúng: beautiful(O) small(S) old(A) round(Sh) Italian(N) silver(M) necklace.</div>"}, {"id": "adjerr_p1_7", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "We need a ", "B": "big comfortable", "C": " antique brown wooden dining table for our kitchen.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "comfortable big", "vi": "Chúng ta cần một chiếc bàn ăn thoải mái, to, cổ, màu nâu, bằng gỗ cho nhà bếp.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>comfortable big</u>\"</div><div class=\"ex-card mb-2\">We need a <u>comfortable big</u> antique brown wooden dining table for our kitchen.<br><span style=\"color:var(--accent);font-size:13px\">Chúng ta cần một chiếc bàn ăn thoải mái, to, cổ, màu nâu, bằng gỗ cho nhà bếp.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Opinion (comfortable) phải đứng TRƯỚC Size (big).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"big comfortable\" sai thứ tự vì Opinion luôn đứng đầu tiên, trước Size → phải sửa thành \"comfortable big\".</div>"}, {"id": "adjerr_p1_8", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "He seems ", "B": "unhappily", "C": " with the decision made by the committee.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "unhappy", "vi": "Anh ấy có vẻ không hài lòng với quyết định của ủy ban.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>unhappy</u>\"</div><div class=\"ex-card mb-2\">He seems <u>unhappy</u> with the decision made by the committee.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy có vẻ không hài lòng với quyết định của ủy ban.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Sau động từ liên kết (seem, look, feel, sound...) dùng TÍNH TỪ, không dùng trạng từ.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"seems\" là động từ liên kết (linking verb) nên phải theo sau bởi tính từ \"unhappy\", không phải trạng từ \"unhappily\".</div>"}, {"id": "adjerr_p1_9", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "You look ", "B": "exhaustingly", "C": ". Have you been working late again?", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "exhausted", "vi": "Trông bạn có vẻ kiệt sức. Bạn lại làm việc muộn nữa à?", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>exhausted</u>\"</div><div class=\"ex-card mb-2\">You look <u>exhausted</u>. Have you been working late again?<br><span style=\"color:var(--accent);font-size:13px\">Trông bạn có vẻ kiệt sức. Bạn lại làm việc muộn nữa à?</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Người CẢM THẤY mệt → dùng đuôi -ed (exhausted); vật GÂY RA mệt → dùng đuôi -ing (exhausting).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"exhaustingly\" vừa sai dạng (là trạng từ, không đi sau linking verb \"look\") vừa sai nghĩa; cần tính từ \"exhausted\" để chỉ cảm giác kiệt sức của người nói.</div>"}, {"id": "adjerr_p1_10", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "You should keep the room ", "B": "cleanly", "C": " to avoid getting sick.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "clean", "vi": "Bạn nên giữ căn phòng sạch sẽ để tránh bị ốm.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>clean</u>\"</div><div class=\"ex-card mb-2\">You should keep the room <u>clean</u> to avoid getting sick.<br><span style=\"color:var(--accent);font-size:13px\">Bạn nên giữ căn phòng sạch sẽ để tránh bị ốm.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Cấu trúc \"keep + O + Adj\" cần tính từ, không dùng trạng từ.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"cleanly\" là trạng từ; trong cấu trúc \"keep + O + Adj\" (giữ cho vật/người ở trạng thái nào đó), cần tính từ \"clean\".</div>"}, {"id": "adjerr_p1_11", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "I find it ", "B": "frightened", "C": " to watch horror films alone.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "frightening", "vi": "Tôi thấy việc xem phim kinh dị một mình thật đáng sợ.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>frightening</u>\"</div><div class=\"ex-card mb-2\">I find it <u>frightening</u> to watch horror films alone.<br><span style=\"color:var(--accent);font-size:13px\">Tôi thấy việc xem phim kinh dị một mình thật đáng sợ.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Việc/vật GÂY RA cảm giác sợ hãi → dùng đuôi -ing (frightening).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Chủ thể ở đây là hành động \"watch horror films alone\" — hành động này GÂY RA nỗi sợ, nên cần \"frightening\", không dùng \"frightened\" (chỉ cảm xúc của người).</div>"}, {"id": "adjerr_p1_12", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "He wants to go somewhere ", "B": "quite", "C": " to relax after a long day.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "quiet", "vi": "Anh ấy muốn đến một nơi yên tĩnh để thư giãn sau một ngày dài.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>quiet</u>\"</div><div class=\"ex-card mb-2\">He wants to go somewhere <u>quiet</u> to relax after a long day.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy muốn đến một nơi yên tĩnh để thư giãn sau một ngày dài.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Phân biệt \"quite\" (trạng từ chỉ mức độ = khá) và \"quiet\" (tính từ = yên tĩnh).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Sau đại từ bất định \"somewhere\" cần một TÍNH TỪ mang nghĩa \"yên tĩnh\": \"quiet\", không phải \"quite\" (khá, một từ hoàn toàn khác nghĩa dù viết gần giống).</div>"}, {"id": "adjerr_p1_13", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "Did you find anything ", "B": "usefully", "C": " at the store?", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "useful", "vi": "Bạn có tìm thấy thứ gì hữu ích ở cửa hàng không?", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>useful</u>\"</div><div class=\"ex-card mb-2\">Did you find anything <u>useful</u> at the store?<br><span style=\"color:var(--accent);font-size:13px\">Bạn có tìm thấy thứ gì hữu ích ở cửa hàng không?</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Tính từ đứng sau đại từ bất định (anything, something, nothing...).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"usefully\" là trạng từ; sau \"anything\" cần tính từ \"useful\".</div>"}, {"id": "adjerr_p1_14", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "There is nothing ", "B": "interestingly", "C": " to watch on TV tonight.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "interesting", "vi": "Không có gì thú vị để xem trên TV tối nay.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>interesting</u>\"</div><div class=\"ex-card mb-2\">There is nothing <u>interesting</u> to watch on TV tonight.<br><span style=\"color:var(--accent);font-size:13px\">Không có gì thú vị để xem trên TV tối nay.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Tính từ đứng sau đại từ bất định \"nothing\".</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"interestingly\" là trạng từ; sau \"nothing\" cần tính từ \"interesting\" (thú vị).</div>"}, {"id": "adjerr_p1_15", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "I need someone ", "B": "reliably", "C": " to help me with this project.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "reliable", "vi": "Tôi cần một người đáng tin cậy để giúp tôi với dự án này.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>reliable</u>\"</div><div class=\"ex-card mb-2\">I need someone <u>reliable</u> to help me with this project.<br><span style=\"color:var(--accent);font-size:13px\">Tôi cần một người đáng tin cậy để giúp tôi với dự án này.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Tính từ đứng sau đại từ bất định \"someone\".</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"reliably\" là trạng từ; sau \"someone\" cần tính từ \"reliable\" (đáng tin cậy).</div>"}, {"id": "adjerr_p1_16", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The proposal was ", "B": "successful highly", "C": ", exceeding everyone's expectations.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "highly successful", "vi": "Đề xuất đã rất thành công, vượt quá mong đợi của mọi người.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>highly successful</u>\"</div><div class=\"ex-card mb-2\">The proposal was <u>highly successful</u>, exceeding everyone's expectations.<br><span style=\"color:var(--accent);font-size:13px\">Đề xuất đã rất thành công, vượt quá mong đợi của mọi người.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Trạng từ chỉ mức độ (highly) đứng TRƯỚC tính từ mà nó bổ nghĩa.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"successful highly\" sai thứ tự; trạng từ \"highly\" phải đứng trước tính từ \"successful\" → \"highly successful\".</div>"}, {"id": "adjerr_p1_17", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "She felt ", "B": "deep disappointed", "C": " when she didn't get the promotion.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "deeply disappointed", "vi": "Cô ấy cảm thấy vô cùng thất vọng khi không được thăng chức.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>deeply disappointed</u>\"</div><div class=\"ex-card mb-2\">She felt <u>deeply disappointed</u> when she didn't get the promotion.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy cảm thấy vô cùng thất vọng khi không được thăng chức.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Cần TRẠNG TỪ (không phải tính từ) để bổ nghĩa cho tính từ \"disappointed\".</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"deep\" là tính từ; để bổ nghĩa cho tính từ khác (disappointed) cần trạng từ \"deeply\" (sâu sắc, vô cùng).</div>"}, {"id": "adjerr_p1_18", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The weather was ", "B": "terribly", "C": " yesterday, so we stayed indoors.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "terrible", "vi": "Thời tiết hôm qua thật tồi tệ, vì vậy chúng tôi ở trong nhà.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>terrible</u>\"</div><div class=\"ex-card mb-2\">The weather was <u>terrible</u> yesterday, so we stayed indoors.<br><span style=\"color:var(--accent);font-size:13px\">Thời tiết hôm qua thật tồi tệ, vì vậy chúng tôi ở trong nhà.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Sau động từ liên kết \"was\" cần tính từ, không dùng trạng từ.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"terribly\" là trạng từ; sau linking verb \"was\" cần tính từ \"terrible\" (tồi tệ).</div>"}, {"id": "adjerr_p1_19", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "She was absent ", "B": "for", "C": " school yesterday because she caught a cold.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "from", "vi": "Cô ấy đã vắng mặt ở trường ngày hôm qua vì bị cảm lạnh.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>from</u>\"</div><div class=\"ex-card mb-2\">She was absent <u>from</u> school yesterday because she caught a cold.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy đã vắng mặt ở trường ngày hôm qua vì bị cảm lạnh.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Cấu trúc cố định: Be absent FROM sth (vắng mặt ở đâu).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Giới từ đúng đi với \"absent\" là FROM, không phải FOR: \"absent from school\".</div>"}, {"id": "adjerr_p1_20", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "Paris is ", "B": "well-know", "C": " for its beautiful landmarks and romantic atmosphere.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "well-known", "vi": "Paris nổi tiếng với những địa danh xinh đẹp và bầu không khí lãng mạn.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>well-known</u>\"</div><div class=\"ex-card mb-2\">Paris is <u>well-known</u> for its beautiful landmarks and romantic atmosphere.<br><span style=\"color:var(--accent);font-size:13px\">Paris nổi tiếng với những địa danh xinh đẹp và bầu không khí lãng mạn.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Cấu trúc WELL + quá khứ phân từ (PII): well-known (nổi tiếng), không phải \"well-know\".</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"well-know\" là lỗi chính tả/dạng từ; đúng phải là \"well-known\" (WELL + known, quá khứ phân từ của \"know\").</div>"}];
const ADJ_PHAN2_Q = [{"id": "adj_phan2_1", "type": "fill", "q": "The __________ in renewable energy is a positive sign for the environment.", "vi": "", "opts": ["A. growing interest", "B. interest growing", "C. growing interested", "D. grown interest"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. growing interest</div><div class=\"ex-card mb-3\">The <b>growing interest</b> in renewable energy is a positive sign for the environment.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ A. growing interest</div><span style=\"color:var(--accent);font-size:12px\">/ˈgrəʊɪŋ ˈɪntrəst/</span> <button onclick=\"speakEnglish('growing interest')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">sự quan tâm ngày càng tăng</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">'growing' (hiện tại phân từ, chủ động) làm tính từ đứng trước danh từ 'interest' → đúng ngữ pháp và nghĩa</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ B. interest growing</div><span style=\"color:var(--accent);font-size:12px\">/ˈɪntrəst ˈgrəʊɪŋ/</span> <button onclick=\"speakEnglish('interest growing')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai trật tự — tính từ phân từ phải đứng TRƯỚC danh từ</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ C. growing interested</div><span style=\"color:var(--accent);font-size:12px\">/ˈgrəʊɪŋ ɪnˈtrəstɪd/</span> <button onclick=\"speakEnglish('growing interested')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">'interested' chỉ cảm xúc con người, không dùng cho danh từ trừu tượng 'interest'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. grown interest</div><span style=\"color:var(--accent);font-size:12px\">/grəʊn ˈɪntrəst/</span> <button onclick=\"speakEnglish('grown interest')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">'grown' (quá khứ phân từ) mang nghĩa bị động, không hợp lý ở đây</div></div>"}, {"id": "adj_phan2_2", "type": "fill", "q": "The __________ window needs to be repaired as soon as possible.", "vi": "", "opts": ["A. break", "B. broke", "C. broken", "D. breaking"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. broken</div><div class=\"ex-card mb-3\">The <b>broken</b> window needs to be repaired as soon as possible.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ A. break</div><span style=\"color:var(--accent);font-size:12px\">/breɪk/</span> <button onclick=\"speakEnglish('break')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">làm vỡ (động từ nguyên mẫu)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không phải tính từ, không đứng trước danh từ theo cách này</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ B. broke</div><span style=\"color:var(--accent);font-size:12px\">/brəʊk/</span> <button onclick=\"speakEnglish('broke')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">(quá khứ đơn của break, không dùng làm tính từ)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không phải dạng tính từ chuẩn</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ C. broken</div><span style=\"color:var(--accent);font-size:12px\">/ˈbrəʊkən/</span> <button onclick=\"speakEnglish('broken')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">bị vỡ, hỏng</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">quá khứ phân từ (PII) làm tính từ mang nghĩa BỊ ĐỘNG: cửa sổ 'bị vỡ' → 'the broken window'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. breaking</div><span style=\"color:var(--accent);font-size:12px\">/ˈbreɪkɪŋ/</span> <button onclick=\"speakEnglish('breaking')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">đang vỡ (chủ động, không hợp nghĩa với vật vô tri)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai nghĩa — cửa sổ không tự 'đang làm vỡ' mà là BỊ vỡ</div></div>"}, {"id": "adj_phan2_3", "type": "fill", "q": "She felt __________ for the job interview, having researched the company thoroughly.", "vi": "", "opts": ["A. ill-prepared", "B. well-prepared", "C. well-preparedly", "D. ill-preparedly"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. well-prepared</div><div class=\"ex-card mb-3\">She felt <b>well-prepared</b> for the job interview, having researched the company thoroughly.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ A. ill-prepared</div><span style=\"color:var(--accent);font-size:12px\">/ˌɪl prɪˈpeəd/</span> <button onclick=\"speakEnglish('ill-prepared')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">chuẩn bị kém</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trái nghĩa với ngữ cảnh 'having researched thoroughly' (đã nghiên cứu kỹ)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ B. well-prepared</div><span style=\"color:var(--accent);font-size:12px\">/ˌwel prɪˈpeəd/</span> <button onclick=\"speakEnglish('well-prepared')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">chuẩn bị kỹ lưỡng</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">'well + PII' = well-prepared, khớp với 'having researched the company thoroughly'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ C. well-preparedly</div><div class=\"mt-1\" style=\"font-size:13px\">(không tồn tại dạng trạng từ này)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không phải từ đúng, WELL+PII đã là tính từ hoàn chỉnh, không thêm -ly</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. ill-preparedly</div><div class=\"mt-1\" style=\"font-size:13px\">(không tồn tại dạng trạng từ này)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không phải từ đúng</div></div>"}, {"id": "adj_phan2_4", "type": "fill", "q": "After living abroad for a year, she started feeling ___________ and missed her family.", "vi": "", "opts": ["A. homemade", "B. homesick", "C. heartbroken", "D. trouble-minded"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. homesick</div><div class=\"ex-card mb-3\">After living abroad for a year, she started feeling <b>homesick</b> and missed her family.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ A. homemade</div><span style=\"color:var(--accent);font-size:12px\">/ˌhəʊmˈmeɪd/</span> <button onclick=\"speakEnglish('homemade')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">làm tại nhà, tự làm</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai nghĩa hoàn toàn — 'homemade' mô tả đồ vật, không phải cảm xúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ B. homesick</div><span style=\"color:var(--accent);font-size:12px\">/ˈhəʊmsɪk/</span> <button onclick=\"speakEnglish('homesick')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">nhớ nhà</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">N+PII/tính từ ghép \"homesick\" (home+sick) = nhớ nhà, khớp với 'missed her family'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ C. heartbroken</div><span style=\"color:var(--accent);font-size:12px\">/ˈhɑːtbrəʊkən/</span> <button onclick=\"speakEnglish('heartbroken')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">đau lòng, tan vỡ trái tim</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai nghĩa — thường dùng cho chuyện tình cảm tan vỡ, không phải nhớ nhà</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. trouble-minded</div><div class=\"mt-1\" style=\"font-size:13px\">lo âu, bối rối (không phải cụm chuẩn phổ biến)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không khớp nghĩa 'nhớ nhà'</div></div>"}, {"id": "adj_phan2_5", "type": "fill", "q": "He was so ___________ about the concert that he forgot to bring his tickets.", "vi": "", "opts": ["A. excitingly", "B. exciting", "C. overexcited", "D. excitedly"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: C. overexcited</div><div class=\"ex-card mb-3\">He was so <b>overexcited</b> about the concert that he forgot to bring his tickets.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ A. excitingly</div><span style=\"color:var(--accent);font-size:12px\">/ɪkˈsaɪtɪŋli/</span> <button onclick=\"speakEnglish('excitingly')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">(trạng từ, không đứng sau 'so' theo cấu trúc này)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cần tính từ sau 'so', không dùng trạng từ</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ B. exciting</div><span style=\"color:var(--accent);font-size:12px\">/ɪkˈsaɪtɪŋ/</span> <button onclick=\"speakEnglish('exciting')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">gây hào hứng (mô tả vật/việc, không phải cảm xúc người)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">'he' là người CẢM THẤY, không phải vật GÂY hào hứng → sai nghĩa</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ C. overexcited</div><span style=\"color:var(--accent);font-size:12px\">/ˌəʊvərɪkˈsaɪtɪd/</span> <button onclick=\"speakEnglish('overexcited')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">phấn khích quá mức</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tiền tố OVER- + excited = quá phấn khích, khớp hoàn hảo với hệ quả 'forgot to bring his tickets' (quá phấn khích đến mức quên vé)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. excitedly</div><span style=\"color:var(--accent);font-size:12px\">/ɪkˈsaɪtɪdli/</span> <button onclick=\"speakEnglish('excitedly')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">(trạng từ, không đứng sau 'so' theo cấu trúc này)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cần tính từ sau 'so...that', không dùng trạng từ</div></div>"}, {"id": "adj_phan2_6", "type": "fill", "q": "He was __________ to finally meet his long-lost friend after many years.", "vi": "", "opts": ["A. happy", "B. unhappy", "C. happily", "D. unhappily"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. happy</div><div class=\"ex-card mb-3\">He was <b>happy</b> to finally meet his long-lost friend after many years.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ A. happy</div><span style=\"color:var(--accent);font-size:12px\">/ˈhæpi/</span> <button onclick=\"speakEnglish('happy')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">vui, hạnh phúc</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sau linking verb 'was' cần tính từ; 'happy to do sth' = vui khi làm gì, khớp nghĩa tích cực của câu</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ B. unhappy</div><span style=\"color:var(--accent);font-size:12px\">/ʌnˈhæpi/</span> <button onclick=\"speakEnglish('unhappy')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">không vui, buồn</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trái nghĩa, không hợp ngữ cảnh 'gặp lại bạn cũ sau nhiều năm'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ C. happily</div><span style=\"color:var(--accent);font-size:12px\">/ˈhæpɪli/</span> <button onclick=\"speakEnglish('happily')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">(trạng từ, không đứng sau linking verb 'was')</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai dạng từ — cần tính từ sau 'was', không dùng trạng từ</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. unhappily</div><span style=\"color:var(--accent);font-size:12px\">/ʌnˈhæpɪli/</span> <button onclick=\"speakEnglish('unhappily')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">(trạng từ, sai dạng và sai nghĩa)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai cả dạng từ và nghĩa</div></div>"}, {"id": "adj_phan2_7", "type": "fill", "q": "The __________ is very popular among photographers.", "vi": "", "opts": ["A. expensive camera digital", "B. digital camera expensive", "C. camera digital expensive", "D. expensive digital camera"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: D. expensive digital camera</div><div class=\"ex-card mb-3\">The <b>expensive digital camera</b> is very popular among photographers.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ A. expensive camera digital</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai trật tự — 'digital' (chất liệu/loại) phải đứng ngay trước danh từ chính 'camera'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ B. digital camera expensive</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai trật tự — tính từ ý kiến 'expensive' phải đứng đầu tiên</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ C. camera digital expensive</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai hoàn toàn trật tự — danh từ chính phải đứng cuối cùng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ D. expensive digital camera</div><span style=\"color:var(--accent);font-size:12px\">/ɪkˈspensɪv ˈdɪdʒɪtl ˈkæmərə/</span> <button onclick=\"speakEnglish('expensive digital camera')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">máy ảnh kỹ thuật số đắt tiền</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">expensive(Opinion) + digital(chất liệu/loại — Material) + camera(danh từ chính) → đúng trật tự OSASCOMP</div></div>"}, {"id": "adj_phan2_8", "type": "fill", "q": "She gave a ____________ to her friend on her birthday.", "vi": "", "opts": ["A. beautiful flower bouquet", "B. flower beautiful bouquet", "C. flower bouquet beautiful", "D. beautiful bouquet flower"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. beautiful flower bouquet</div><div class=\"ex-card mb-3\">She gave a <b>beautiful flower bouquet</b> to her friend on her birthday.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ A. beautiful flower bouquet</div><span style=\"color:var(--accent);font-size:12px\">/ˈbjuːtɪfl ˈflaʊər buːˈkeɪ/</span> <button onclick=\"speakEnglish('beautiful flower bouquet')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">bó hoa đẹp</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">beautiful(Opinion) + flower(danh từ phân loại 'hoa') + bouquet(danh từ chính 'bó hoa') → đúng trật tự</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ B. flower beautiful bouquet</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai trật tự — Opinion phải đứng đầu tiên</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ C. flower bouquet beautiful</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai trật tự — tính từ không đứng sau danh từ chính</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. beautiful bouquet flower</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai trật tự — danh từ phân loại 'flower' phải đứng ngay trước danh từ chính 'bouquet', không đứng sau</div></div>"}, {"id": "adj_phan2_9", "type": "fill", "q": "The company launched a _________________to enhance customer experience.", "vi": "", "opts": ["A. new convenient mobile app", "B. convenient new mobile app", "C. convenient mobile new app", "D. mobile app convenient new"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: B. convenient new mobile app</div><div class=\"ex-card mb-3\">The company launched a <b>convenient new mobile app</b>to enhance customer experience.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ A. new convenient mobile app</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai trật tự — Opinion (convenient) phải đứng trước Age (new)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ B. convenient new mobile app</div><span style=\"color:var(--accent);font-size:12px\">/kənˈviːniənt njuː ˈməʊbaɪl æp/</span> <button onclick=\"speakEnglish('convenient new mobile app')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">ứng dụng di động mới tiện lợi</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">convenient(Opinion) + new(Age) + mobile(danh từ phân loại 'di động') + app(danh từ chính) → đúng trật tự OSASCOMP</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ C. convenient mobile new app</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai trật tự — Age (new) phải đứng trước danh từ phân loại (mobile), không đứng sau</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. mobile app convenient new</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sai hoàn toàn trật tự — các tính từ phải đứng trước danh từ, không đứng sau</div></div>"}, {"id": "adj_phan2_10", "type": "fill", "q": "The new software is ____________ of processing large amounts of data in seconds.", "vi": "", "opts": ["A. capable", "B. able", "C. possible", "D. All are correct"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Đáp án đúng: A. capable</div><div class=\"ex-card mb-3\">The new software is <b>capable</b> of processing large amounts of data in seconds.</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">📚 Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">✅ A. capable</div><span style=\"color:var(--accent);font-size:12px\">/ˈkeɪpəbl/</span> <button onclick=\"speakEnglish('capable')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">có khả năng</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">'be capable of doing sth' = có khả năng làm gì → đúng cấu trúc với giới từ OF + V-ing đã cho sẵn</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ B. able</div><span style=\"color:var(--accent);font-size:12px\">/ˈeɪbl/</span> <button onclick=\"speakEnglish('able')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">có thể, có khả năng</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">'be able TO DO sth' cần TO + động từ nguyên mẫu, không đi với OF + V-ing</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ C. possible</div><span style=\"color:var(--accent);font-size:12px\">/ˈpɒsəbl/</span> <button onclick=\"speakEnglish('possible')\" class=\"icon-toggle\" style=\"width:24px;height:24px;display:inline-flex;vertical-align:middle;margin-left:4px;font-size:12px\">🔊</button><div class=\"mt-1\" style=\"font-size:13px\">có thể (dùng cho sự việc, không dùng cho chủ ngữ là người/vật có khả năng)</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">'possible' đi với cấu trúc 'It is possible for sb to do sth', không dùng trực tiếp 'sth is possible of doing'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">▫️ D. All are correct</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">chỉ 'capable of doing sth' khớp đúng cấu trúc giới từ OF + V-ing đã cho sẵn trong câu</div></div>"}];
const ADJ_DAY25_Q = [{"id": "adjerr_d25_1", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The ", "B": "small delicious", "C": " oval white Japanese plate was a gift from my grandmother.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "delicious small", "vi": "Chiếc đĩa nhỏ, ngon mắt, hình bầu dục, màu trắng của Nhật là món quà từ bà tôi.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>delicious small</u>\"</div><div class=\"ex-card mb-2\">The <u>delicious small</u> oval white Japanese plate was a gift from my grandmother.<br><span style=\"color:var(--accent);font-size:13px\">Chiếc đĩa nhỏ, ngon mắt, hình bầu dục, màu trắng của Nhật là món quà từ bà tôi.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Opinion luôn đứng đầu tiên, trước Size.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"small delicious\" sai thứ tự vì Opinion (delicious) phải đứng trước Size (small) → sửa thành \"delicious small\".</div>"}, {"id": "adjerr_d25_2", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The police increased patrols in the area for ", "B": "security urgent", "C": " reasons.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "urgent security", "vi": "Cảnh sát đã tăng cường tuần tra trong khu vực vì các lý do an ninh khẩn cấp.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>urgent security</u>\"</div><div class=\"ex-card mb-2\">The police increased patrols in the area for <u>urgent security</u> reasons.<br><span style=\"color:var(--accent);font-size:13px\">Cảnh sát đã tăng cường tuần tra trong khu vực vì các lý do an ninh khẩn cấp.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Tính từ ý kiến/mức độ ưu tiên (urgent) đứng trước danh từ phân loại (security) trong cụm danh từ ghép.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"security urgent\" sai thứ tự; \"urgent\" (khẩn cấp – Opinion) phải đứng trước \"security\" (an ninh – danh từ phân loại): \"urgent security reasons\".</div>"}, {"id": "adjerr_d25_3", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The ", "B": "stock market global", "C": " is experiencing significant fluctuations today.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "global stock market", "vi": "Thị trường chứng khoán toàn cầu đang trải qua những biến động đáng kể hôm nay.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>global stock market</u>\"</div><div class=\"ex-card mb-2\">The <u>global stock market</u> is experiencing significant fluctuations today.<br><span style=\"color:var(--accent);font-size:13px\">Thị trường chứng khoán toàn cầu đang trải qua những biến động đáng kể hôm nay.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Tính từ đứng TRƯỚC danh từ mà nó bổ nghĩa, không đứng sau.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"stock market global\" sai vị trí; \"global\" (toàn cầu) phải đứng trước cụm danh từ \"stock market\": \"the global stock market\".</div>"}, {"id": "adjerr_d25_4", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The idea sounds ", "B": "interestingly", "C": "; I'd like to know more about it.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "interesting", "vi": "Ý tưởng nghe có vẻ thú vị; tôi muốn biết thêm về nó.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>interesting</u>\"</div><div class=\"ex-card mb-2\">The idea sounds <u>interesting</u>; I'd like to know more about it.<br><span style=\"color:var(--accent);font-size:13px\">Ý tưởng nghe có vẻ thú vị; tôi muốn biết thêm về nó.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Sau động từ tri giác \"sounds\" cần tính từ, không dùng trạng từ.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"interestingly\" là trạng từ; sau linking verb \"sounds\" cần tính từ \"interesting\".</div>"}, {"id": "adjerr_d25_5", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "He looked ", "B": "confusing", "C": " when I explained the instructions.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "confused", "vi": "Anh ấy trông có vẻ bối rối khi tôi giải thích hướng dẫn.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>confused</u>\"</div><div class=\"ex-card mb-2\">He looked <u>confused</u> when I explained the instructions.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy trông có vẻ bối rối khi tôi giải thích hướng dẫn.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Người CẢM THẤY bối rối → dùng -ed; vật/việc GÂY RA bối rối → dùng -ing.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Chủ ngữ \"he\" là người CẢM THẤY bối rối nên cần \"confused\", không dùng \"confusing\" (chỉ vật/việc gây bối rối).</div>"}, {"id": "adjerr_d25_6", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "A ", "B": "bored", "C": " man like him usually struggles to make friends because people find him hard to talk to.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "boring", "vi": "Một người đàn ông nhàm chán như anh ta thường gặp khó khăn trong việc kết bạn vì mọi người thấy khó nói chuyện với anh ta.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>boring</u>\"</div><div class=\"ex-card mb-2\">A <u>boring</u> man like him usually struggles to make friends because people find him hard to talk to.<br><span style=\"color:var(--accent);font-size:13px\">Một người đàn ông nhàm chán như anh ta thường gặp khó khăn trong việc kết bạn vì mọi người thấy khó nói chuyện với anh ta.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Người/vật GÂY nhàm chán cho người khác → dùng -ing (boring); người CẢM THẤY nhàm chán → dùng -ed (bored).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Ngữ cảnh \"people find him hard to talk to\" cho thấy người đàn ông này GÂY RA sự nhàm chán cho người khác → cần \"boring\", không dùng \"bored\".</div>"}, {"id": "adjerr_d25_7", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "She remained ", "B": "calmly", "C": " throughout the entire exam, which helped her perform well.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "calm", "vi": "Cô ấy giữ bình tĩnh suốt bài thi, điều đó giúp cô làm bài tốt.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>calm</u>\"</div><div class=\"ex-card mb-2\">She remained <u>calm</u> throughout the entire exam, which helped her perform well.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy giữ bình tĩnh suốt bài thi, điều đó giúp cô làm bài tốt.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Sau động từ liên kết \"remain\" cần tính từ, không dùng trạng từ.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"remain\" là linking verb (vẫn còn, giữ ở trạng thái nào đó) nên cần theo sau bởi tính từ \"calm\", không phải trạng từ \"calmly\".</div>"}, {"id": "adjerr_d25_8", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "Nothing ", "B": "specialty", "C": " happened during the trip, but it was still relaxing.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "special", "vi": "Không có gì đặc biệt xảy ra trong chuyến đi, nhưng nó vẫn thư giãn.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>special</u>\"</div><div class=\"ex-card mb-2\">Nothing <u>special</u> happened during the trip, but it was still relaxing.<br><span style=\"color:var(--accent);font-size:13px\">Không có gì đặc biệt xảy ra trong chuyến đi, nhưng nó vẫn thư giãn.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Tính từ đứng sau đại từ bất định \"nothing\".</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"specialty\" là danh từ (chuyên môn, đặc sản); sau \"nothing\" cần tính từ \"special\" (đặc biệt).</div>"}, {"id": "adjerr_d25_9", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "Everyone ", "B": "excitingly", "C": " about the concert waited eagerly for the doors to open.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "excited", "vi": "Mọi người hào hứng về buổi hòa nhạc đã háo hức chờ cửa mở.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>excited</u>\"</div><div class=\"ex-card mb-2\">Everyone <u>excited</u> about the concert waited eagerly for the doors to open.<br><span style=\"color:var(--accent);font-size:13px\">Mọi người hào hứng về buổi hòa nhạc đã háo hức chờ cửa mở.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Người CẢM THẤY hào hứng → dùng -ed (excited); vật GÂY hào hứng → dùng -ing (exciting).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"Everyone\" là người CẢM THẤY hào hứng nên cần tính từ \"excited\", không dùng trạng từ \"excitingly\" (sai cả dạng từ lẫn nghĩa).</div>"}, {"id": "adjerr_d25_10", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "His explanation was ", "B": "clear perfectly", "C": " and easy to follow.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "perfectly clear", "vi": "Lời giải thích của anh ấy rõ ràng hoàn hảo và dễ hiểu.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>perfectly clear</u>\"</div><div class=\"ex-card mb-2\">His explanation was <u>perfectly clear</u> and easy to follow.<br><span style=\"color:var(--accent);font-size:13px\">Lời giải thích của anh ấy rõ ràng hoàn hảo và dễ hiểu.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Trạng từ chỉ mức độ đứng TRƯỚC tính từ mà nó bổ nghĩa.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"clear perfectly\" sai thứ tự; trạng từ \"perfectly\" phải đứng trước tính từ \"clear\" → \"perfectly clear\".</div>"}, {"id": "adjerr_d25_11", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The weather today is very cold, so don't forget to wear a ", "B": "warmly", "C": " coat.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "warm", "vi": "Thời tiết hôm nay rất lạnh, vì vậy đừng quên mặc một chiếc áo khoác ấm.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>warm</u>\"</div><div class=\"ex-card mb-2\">The weather today is very cold, so don't forget to wear a <u>warm</u> coat.<br><span style=\"color:var(--accent);font-size:13px\">Thời tiết hôm nay rất lạnh, vì vậy đừng quên mặc một chiếc áo khoác ấm.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Tính từ đứng trước danh từ để bổ nghĩa, không dùng trạng từ.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"warmly\" là trạng từ; trước danh từ \"coat\" cần tính từ \"warm\" (ấm áp).</div>"}, {"id": "adjerr_d25_12", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The food at the new restaurant is ", "B": "deliciously", "C": ", and I highly recommend it to anyone.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "delicious", "vi": "Đồ ăn ở nhà hàng mới rất ngon, và tôi thực sự giới thiệu nó cho mọi người.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>delicious</u>\"</div><div class=\"ex-card mb-2\">The food at the new restaurant is <u>delicious</u>, and I highly recommend it to anyone.<br><span style=\"color:var(--accent);font-size:13px\">Đồ ăn ở nhà hàng mới rất ngon, và tôi thực sự giới thiệu nó cho mọi người.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Sau động từ liên kết \"is\" cần tính từ, không dùng trạng từ.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"deliciously\" là trạng từ; sau \"is\" cần tính từ \"delicious\" (ngon).</div>"}, {"id": "adjerr_d25_13", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "After years of trying to have children, they eventually decided to remain ", "B": "childish", "C": ", focusing on their careers instead.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "childless", "vi": "Sau nhiều năm cố gắng có con, cuối cùng họ quyết định không có con, tập trung vào sự nghiệp thay vào đó.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>childless</u>\"</div><div class=\"ex-card mb-2\">After years of trying to have children, they eventually decided to remain <u>childless</u>, focusing on their careers instead.<br><span style=\"color:var(--accent);font-size:13px\">Sau nhiều năm cố gắng có con, cuối cùng họ quyết định không có con, tập trung vào sự nghiệp thay vào đó.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Phân biệt hậu tố -less (không có) và -ish (mang tính chất trẻ con).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"childish\" nghĩa là \"trẻ con, ấu trĩ\" — sai nghĩa hoàn toàn; câu cần \"childless\" (-less: không có con) để phù hợp ngữ cảnh \"trying to have children\".</div>"}, {"id": "adjerr_d25_14", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "Many people who are ", "B": "underweight", "C": " struggle with health problems like high blood pressure and diabetes.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "overweight", "vi": "Nhiều người thừa cân gặp khó khăn với các vấn đề sức khỏe như huyết áp cao và tiểu đường.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>overweight</u>\"</div><div class=\"ex-card mb-2\">Many people who are <u>overweight</u> struggle with health problems like high blood pressure and diabetes.<br><span style=\"color:var(--accent);font-size:13px\">Nhiều người thừa cân gặp khó khăn với các vấn đề sức khỏe như huyết áp cao và tiểu đường.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Kiến thức thực tế: cao huyết áp và tiểu đường thường liên quan đến THỪA cân, không phải THIẾU cân.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"underweight\" (thiếu cân, tiền tố under-) không hợp lý về nghĩa với \"high blood pressure and diabetes\" — các bệnh này thường gắn với \"overweight\" (thừa cân, tiền tố over-).</div>"}, {"id": "adjerr_d25_15", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "After spending the whole day at the beach, I got ", "B": "burning", "C": " on my shoulders.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "sunburned", "vi": "Sau khi dành cả ngày ở biển, tôi bị cháy nắng ở vai.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>sunburned</u>\"</div><div class=\"ex-card mb-2\">After spending the whole day at the beach, I got <u>sunburned</u> on my shoulders.<br><span style=\"color:var(--accent);font-size:13px\">Sau khi dành cả ngày ở biển, tôi bị cháy nắng ở vai.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Cấu trúc Danh từ + Quá khứ phân từ (N+PII): sunburned = bị cháy nắng.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"burning\" (V-ing, đang cháy - chủ động) sai nghĩa và sai dạng; câu cần tính từ ghép \"sunburned\" (sun + burned) diễn tả tình trạng bị cháy nắng.</div>"}, {"id": "adjerr_d25_16", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "She made a ", "B": "well-informed", "C": " comment about the issue without understanding all the facts.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "ill-informed", "vi": "Cô ấy đưa ra một bình luận thiếu hiểu biết về vấn đề đó mà không hiểu hết sự thật.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>ill-informed</u>\"</div><div class=\"ex-card mb-2\">She made a <u>ill-informed</u> comment about the issue without understanding all the facts.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy đưa ra một bình luận thiếu hiểu biết về vấn đề đó mà không hiểu hết sự thật.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Phân biệt WELL+PII (làm tốt/hiểu rõ) và ILL+PII (làm kém/hiểu sai).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"well-informed\" (hiểu biết đầy đủ) mâu thuẫn với vế sau \"without understanding all the facts\" (không hiểu hết sự thật) → phải dùng \"ill-informed\" (thông tin không đầy đủ, kém hiểu biết).</div>"}, {"id": "adjerr_d25_17", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The ", "B": "developed", "C": " countries face many challenges in terms of education and healthcare.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "developing", "vi": "Các nước đang phát triển phải đối mặt với nhiều thách thức về giáo dục và chăm sóc sức khỏe.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>developing</u>\"</div><div class=\"ex-card mb-2\">The <u>developing</u> countries face many challenges in terms of education and healthcare.<br><span style=\"color:var(--accent);font-size:13px\">Các nước đang phát triển phải đối mặt với nhiều thách thức về giáo dục và chăm sóc sức khỏe.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Kiến thức thực tế: các nước ĐANG phát triển (developing) thường gặp nhiều thách thức về giáo dục/y tế hơn nước ĐÃ phát triển (developed).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"developed countries\" (nước đã phát triển) không hợp lý với \"face many challenges in education and healthcare\" — nên dùng \"developing countries\" (nước đang phát triển).</div>"}, {"id": "adjerr_d25_18", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The ", "B": "falling", "C": " leaves covered the ground in a beautiful pattern.", "D": ""}, "active_letters": ["A", "B"], "ans": -1, "correction": "", "vi": "Những chiếc lá đang rơi phủ lên mặt đất thành một họa tiết đẹp mắt.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Câu này không có lỗi sai (câu đúng ngữ pháp)</div><div class=\"ex-card mb-2\">The falling leaves covered the ground in a beautiful pattern.<br><span style=\"color:var(--accent);font-size:13px\">Những chiếc lá đang rơi phủ lên mặt đất thành một họa tiết đẹp mắt.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Câu này ĐÚNG ngữ pháp — không có lỗi sai.</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> \"falling\" là hiện tại phân từ (V-ing) dùng làm tính từ mang nghĩa CHỦ ĐỘNG (lá tự rơi), hoàn toàn chính xác khi đứng trước danh từ \"leaves\": \"the falling leaves\" (những chiếc lá đang rơi).</div>"}, {"id": "adjerr_d25_19", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "She is allergic ", "B": "with", "C": " peanuts, so she always checks the ingredients before eating.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "to", "vi": "Cô ấy bị dị ứng với đậu phộng, vì vậy cô luôn kiểm tra thành phần trước khi ăn.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>to</u>\"</div><div class=\"ex-card mb-2\">She is allergic <u>to</u> peanuts, so she always checks the ingredients before eating.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy bị dị ứng với đậu phộng, vì vậy cô luôn kiểm tra thành phần trước khi ăn.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Cấu trúc cố định: Be allergic TO sth (dị ứng với cái gì).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Giới từ đúng đi với \"allergic\" là TO, không phải WITH.</div>"}, {"id": "adjerr_d25_20", "type": "error", "template": "{A}{B}{C}{D}", "parts": {"A": "The students became quickly acquainted ", "B": "to", "C": " the new software during the training session.", "D": ""}, "active_letters": ["A", "B"], "ans": 1, "correction": "with", "vi": "Các học sinh nhanh chóng làm quen với phần mềm mới trong buổi tập huấn.", "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">✅ Lỗi sai: B — sửa thành \"<u>with</u>\"</div><div class=\"ex-card mb-2\">The students became quickly acquainted <u>with</u> the new software during the training session.<br><span style=\"color:var(--accent);font-size:13px\">Các học sinh nhanh chóng làm quen với phần mềm mới trong buổi tập huấn.</span></div><div class=\"mb-2\"><b class=\"text-dark2\">📐 Quy tắc:</b> Cấu trúc cố định: Be acquainted WITH sth (quen thuộc, thông thạo cái gì).</div><div class=\"mb-2\"><b class=\"text-dark2\">🎯 Giải thích:</b> Giới từ đúng đi với \"acquainted\" là WITH, không phải TO.</div>"}];
